export const EDGE_FUNCTION_CODES: Record<string, string> = {
  "admin-dashboard": "import { createClient } from \"https://esm.sh/@supabase/supabase-js@2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\": \"authorization, x-client-info, apikey, content-type\",\n};\n\nDeno.serve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    const supabaseUrl = Deno.env.get(\"SUPABASE_URL\")!;\n    const serviceRoleKey = Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\")!;\n    const anonKey = Deno.env.get(\"SUPABASE_ANON_KEY\") || Deno.env.get(\"SUPABASE_PUBLISHABLE_KEY\") || \"\";\n\n    const authHeader = req.headers.get(\"Authorization\");\n    if (!authHeader) {\n      return new Response(JSON.stringify({ error: \"Unauthorized\" }), {\n        status: 401, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);\n    const supabaseUser = createClient(supabaseUrl, anonKey, {\n      global: { headers: { Authorization: authHeader } },\n    });\n\n    const { data: { user }, error: userError } = await supabaseUser.auth.getUser();\n    if (userError || !user || user.email !== \"hebertricardo@gmail.com\") {\n      return new Response(JSON.stringify({ error: \"Unauthorized - Admin only\" }), {\n        status: 403, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    const { action, table_name } = await req.json();\n\n    if (action === \"get_metadata\") {\n      const knownTables = [\n        \"profiles\", \"user_credits\", \"credit_transactions\",\n        \"creative_requests\", \"generated_creatives\", \"carousel_requests\",\n        \"email_send_log\", \"email_send_state\", \"email_unsubscribe_tokens\",\n        \"suppressed_emails\"\n      ];\n\n      const tableInfo = [];\n      for (const tableName of knownTables) {\n        const { count } = await supabaseAdmin\n          .from(tableName)\n          .select(\"*\", { count: \"exact\", head: true });\n        tableInfo.push({ name: tableName, row_count: count ?? 0 });\n      }\n\n      const { data: buckets } = await supabaseAdmin.storage.listBuckets();\n\n      return new Response(JSON.stringify({\n        tables: tableInfo,\n        buckets: buckets || [],\n        connection: {\n          supabase_url: supabaseUrl,\n          anon_key: anonKey,\n          project_ref: supabaseUrl.replace(\"https://\", \"\").replace(\".supabase.co\", \"\"),\n        },\n      }), { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } });\n    }\n\n    if (action === \"get_table_data\") {\n      if (!table_name) {\n        return new Response(JSON.stringify({ error: \"table_name required\" }), {\n          status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n      const { data, error } = await supabaseAdmin.from(table_name).select(\"*\").limit(1000);\n      if (error) {\n        return new Response(JSON.stringify({ error: error.message }), {\n          status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n      return new Response(JSON.stringify({ data: data || [] }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    if (action === \"get_table_schema\") {\n      if (!table_name) {\n        return new Response(JSON.stringify({ error: \"table_name required\" }), {\n          status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n      const openApiRes = await fetch(`${supabaseUrl}/rest/v1/`, {\n        headers: {\n          \"apikey\": serviceRoleKey,\n          \"Authorization\": `Bearer ${serviceRoleKey}`,\n          \"Accept\": \"application/openapi+json\",\n        },\n      });\n      let columns: any[] = [];\n      try {\n        const openApi = await openApiRes.json();\n        const tableDef = openApi?.definitions?.[table_name];\n        if (tableDef?.properties) {\n          columns = Object.entries(tableDef.properties).map(([name, def]: [string, any]) => ({\n            name,\n            type: def.format || def.type || \"unknown\",\n            description: def.description || \"\",\n            default: def.default ?? null,\n          }));\n        }\n      } catch {}\n      return new Response(JSON.stringify({ columns }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    if (action === \"get_storage_files\") {\n      const bucket_name = table_name;\n      if (!bucket_name) {\n        return new Response(JSON.stringify({ error: \"bucket name required\" }), {\n          status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n      const { data, error } = await supabaseAdmin.storage.from(bucket_name).list(\"\", { limit: 100 });\n      return new Response(JSON.stringify({ files: data || [], error: error?.message }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    if (action === \"get_function_code\") {\n      const fnName = table_name;\n      if (!fnName) {\n        return new Response(JSON.stringify({ error: \"function name required\" }), {\n          status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n      try {\n        const possiblePaths = [\n          `/home/deno/functions/${fnName}/index.ts`,\n          `/home/deno/functions/${fnName}/index.js`,\n          `/var/task/functions/${fnName}/index.ts`,\n          `/tmp/functions/${fnName}/index.ts`,\n          `./functions/${fnName}/index.ts`,\n          `./${fnName}/index.ts`,\n          `../${fnName}/index.ts`,\n          `/src/functions/${fnName}/index.ts`,\n        ];\n        \n        let code = \"\";\n        let foundPath = \"\";\n        \n        // Try to discover the actual path\n        let debugInfo = \"\";\n        try {\n          const cwd = Deno.cwd();\n          debugInfo += `CWD: ${cwd}\\n`;\n          try {\n            for await (const entry of Deno.readDir(cwd)) {\n              debugInfo += `  ${entry.name} (${entry.isDirectory ? 'dir' : 'file'})\\n`;\n            }\n          } catch {}\n          try {\n            for await (const entry of Deno.readDir(\"/home/deno\")) {\n              debugInfo += `  /home/deno/${entry.name} (${entry.isDirectory ? 'dir' : 'file'})\\n`;\n            }\n          } catch (e) {\n            debugInfo += `  /home/deno: ${e.message}\\n`;\n          }\n        } catch {}\n        \n        for (const p of possiblePaths) {\n          try {\n            code = await Deno.readTextFile(p);\n            foundPath = p;\n            break;\n          } catch { /* try next */ }\n        }\n        \n        if (!code) {\n          // Also try reading relative to import.meta.url\n          try {\n            const baseUrl = new URL(\".\", import.meta.url);\n            const siblingUrl = new URL(`../${fnName}/index.ts`, baseUrl);\n            const resp = await fetch(siblingUrl);\n            if (resp.ok) {\n              code = await resp.text();\n              foundPath = siblingUrl.toString();\n            }\n          } catch {}\n        }\n        \n        if (!code) {\n          code = `// Código não encontrado.\\n// Debug:\\n${debugInfo}`;\n        }\n        \n        return new Response(JSON.stringify({ code, path: foundPath }), {\n          headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      } catch (e) {\n        return new Response(JSON.stringify({ error: e.message }), {\n          status: 500, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        });\n      }\n    }\n\n    return new Response(JSON.stringify({ error: \"Unknown action\" }), {\n      status: 400, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n    });\n  } catch (error) {\n    return new Response(JSON.stringify({ error: error.message }), {\n      status: 500, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n    });\n  }\n});\n",
  "check-user-exists": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport { createClient } from \"npm:@supabase/supabase-js@2.57.2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-webhook-secret\",\n};\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    const webhookSecret = req.headers.get(\"x-webhook-secret\");\n    const expectedSecret = Deno.env.get(\"WEBHOOK_SECRET\");\n    if (!expectedSecret || webhookSecret !== expectedSecret) {\n      return new Response(JSON.stringify({ error: \"Unauthorized\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 401,\n      });\n    }\n\n    const { email } = await req.json();\n\n    if (!email) {\n      return new Response(JSON.stringify({ error: \"email é obrigatório\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const supabaseAdmin = createClient(\n      Deno.env.get(\"SUPABASE_URL\") ?? \"\",\n      Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\") ?? \"\"\n    );\n\n    // Paginate through all users to find by email\n    let user = null;\n    let page = 1;\n    const perPage = 100;\n\n    while (true) {\n      const { data, error } = await supabaseAdmin.auth.admin.listUsers({\n        page,\n        perPage,\n      });\n      if (error) throw error;\n\n      const found = data?.users?.find((u) => u.email === email);\n      if (found) {\n        user = found;\n        break;\n      }\n\n      // No more pages\n      if (!data?.users || data.users.length < perPage) break;\n      page++;\n    }\n\n    console.log(`check-user-exists: email=${email}, found=${!!user}, userId=${user?.id ?? 'none'}`);\n\n    if (user) {\n      const { data: credits } = await supabaseAdmin\n        .from(\"user_credits\")\n        .select(\"credits_balance\")\n        .eq(\"user_id\", user.id)\n        .single();\n\n      return new Response(\n        JSON.stringify({\n          exists: true,\n          userId: user.id,\n          email,\n          creditsBalance: credits?.credits_balance ?? 0,\n        }),\n        { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" }, status: 200 }\n      );\n    }\n\n    return new Response(\n      JSON.stringify({ exists: false, email }),\n      { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" }, status: 200 }\n    );\n  } catch (error) {\n    console.error(\"check-user-exists error:\", error);\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
  "create-checkout": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport Stripe from \"https://esm.sh/stripe@18.5.0\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version\",\n};\n\nconst PRICE_MAP: Record<string, { priceId: string; credits: number }> = {\n  basico: { priceId: \"price_1THpcrIHwK20nCZlGoGCTqAY\", credits: 20 },\n  pro: { priceId: \"price_1THpebIHwK20nCZlHCAAdR8o\", credits: 50 },\n  plus: { priceId: \"price_1THpevIHwK20nCZlN0XaQXGH\", credits: 100 },\n};\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    const { packageId } = await req.json();\n    const pkg = PRICE_MAP[packageId];\n    if (!pkg) throw new Error(\"Pacote inválido\");\n\n    const stripe = new Stripe(Deno.env.get(\"STRIPE_SECRET_KEY\") || \"\", {\n      apiVersion: \"2025-08-27.basil\",\n    });\n\n    const session = await stripe.checkout.sessions.create({\n      line_items: [{ price: pkg.priceId, quantity: 1 }],\n      mode: \"payment\",\n      payment_method_types: [\"card\", \"link\"],\n      success_url: `${req.headers.get(\"origin\")}/payment-success?session_id={CHECKOUT_SESSION_ID}&package=${packageId}`,\n      cancel_url: `${req.headers.get(\"origin\")}/#pricing`,\n      metadata: {\n        credits: pkg.credits.toString(),\n        package: packageId,\n      },\n    });\n\n    return new Response(JSON.stringify({ url: session.url }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 200,\n    });\n  } catch (error) {\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
  "create-user-webhook": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport { createClient } from \"npm:@supabase/supabase-js@2.57.2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-webhook-secret\",\n};\n\nconst CREDITS_MAP: Record<string, number> = {\n  \"PACOTE BASICO\": 20,\n  \"PACOTE PRO\": 50,\n  \"PACOTE PLUS\": 100,\n};\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    // Validate webhook secret\n    const webhookSecret = req.headers.get(\"x-webhook-secret\");\n    const expectedSecret = Deno.env.get(\"WEBHOOK_SECRET\");\n    if (!expectedSecret || webhookSecret !== expectedSecret) {\n      return new Response(JSON.stringify({ error: \"Unauthorized\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 401,\n      });\n    }\n\n    const { email, name, packageId } = await req.json();\n\n    if (!email || !packageId) {\n      return new Response(JSON.stringify({ error: \"email e packageId são obrigatórios\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const credits = CREDITS_MAP[packageId];\n    if (!credits) {\n      return new Response(JSON.stringify({ error: \"packageId inválido. Use: PACOTE BASICO, PACOTE PRO, PACOTE PLUS\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const supabaseAdmin = createClient(\n      Deno.env.get(\"SUPABASE_URL\") ?? \"\",\n      Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\") ?? \"\"\n    );\n\n    // Check if user exists\n    const { data: existingUsers } = await supabaseAdmin.auth.admin.listUsers();\n    const existingUser = existingUsers?.users?.find((u) => u.email === email);\n\n    let userId: string;\n    let isNewUser = false;\n\n    if (existingUser) {\n      userId = existingUser.id;\n\n      const { data: currentCredits } = await supabaseAdmin\n        .from(\"user_credits\")\n        .select(\"credits_balance\")\n        .eq(\"user_id\", userId)\n        .single();\n\n      if (currentCredits) {\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .update({ credits_balance: currentCredits.credits_balance + credits })\n          .eq(\"user_id\", userId);\n      }\n    } else {\n      isNewUser = true;\n\n      const { data: newUser, error: createError } = await supabaseAdmin.auth.admin.createUser({\n        email,\n        password: \"123456\",\n        email_confirm: true,\n        user_metadata: { name: name || email.split(\"@\")[0], must_change_password: true },\n      });\n\n      if (createError || !newUser.user) {\n        throw new Error(\"Erro ao criar conta: \" + (createError?.message || \"desconhecido\"));\n      }\n\n      userId = newUser.user.id;\n\n      // Wait for triggers to create profile and credits\n      await new Promise((resolve) => setTimeout(resolve, 1500));\n\n      const { data: currentCredits } = await supabaseAdmin\n        .from(\"user_credits\")\n        .select(\"credits_balance\")\n        .eq(\"user_id\", userId)\n        .single();\n\n      if (currentCredits) {\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .update({ credits_balance: currentCredits.credits_balance + credits })\n          .eq(\"user_id\", userId);\n      } else {\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .insert({ user_id: userId, credits_balance: credits + 4, credits_used: 0 });\n      }\n    }\n\n    // Log transaction\n    await supabaseAdmin.from(\"credit_transactions\").insert({\n      user_id: userId,\n      amount: credits,\n      type: \"purchase\",\n      description: `Compra de ${credits} créditos via Hotmart (${packageId})`,\n    });\n\n    return new Response(\n      JSON.stringify({ success: true, isNewUser, email, credits }),\n      {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 200,\n      }\n    );\n  } catch (error) {\n    console.error(\"create-user-webhook error:\", error);\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
  "delete-user-refund": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport { createClient } from \"npm:@supabase/supabase-js@2.57.2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-webhook-secret\",\n};\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    const webhookSecret = req.headers.get(\"x-webhook-secret\");\n    const expectedSecret = Deno.env.get(\"WEBHOOK_SECRET\");\n    if (!expectedSecret || webhookSecret !== expectedSecret) {\n      return new Response(JSON.stringify({ error: \"Unauthorized\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 401,\n      });\n    }\n\n    const { email } = await req.json();\n\n    if (!email) {\n      return new Response(JSON.stringify({ error: \"email é obrigatório\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const supabaseAdmin = createClient(\n      Deno.env.get(\"SUPABASE_URL\") ?? \"\",\n      Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\") ?? \"\"\n    );\n\n    // Find user by email\n    let user = null;\n    let page = 1;\n    const perPage = 100;\n\n    while (true) {\n      const { data, error } = await supabaseAdmin.auth.admin.listUsers({ page, perPage });\n      if (error) throw error;\n\n      const found = data?.users?.find((u) => u.email === email);\n      if (found) {\n        user = found;\n        break;\n      }\n      if (!data?.users || data.users.length < perPage) break;\n      page++;\n    }\n\n    if (!user) {\n      console.log(`delete-user-refund: user not found for email=${email}`);\n      return new Response(\n        JSON.stringify({ success: false, error: \"Usuário não encontrado\", email }),\n        { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" }, status: 404 }\n      );\n    }\n\n    const userId = user.id;\n    console.log(`delete-user-refund: deleting user ${userId} (${email})`);\n\n    // Delete related data in order (child tables first)\n    await supabaseAdmin.from(\"generated_creatives\").delete().eq(\"user_id\", userId);\n    await supabaseAdmin.from(\"creative_requests\").delete().eq(\"user_id\", userId);\n    await supabaseAdmin.from(\"carousel_requests\").delete().eq(\"user_id\", userId);\n    await supabaseAdmin.from(\"credit_transactions\").delete().eq(\"user_id\", userId);\n    await supabaseAdmin.from(\"user_credits\").delete().eq(\"user_id\", userId);\n    await supabaseAdmin.from(\"profiles\").delete().eq(\"user_id\", userId);\n\n    // Delete auth user\n    const { error: deleteError } = await supabaseAdmin.auth.admin.deleteUser(userId);\n    if (deleteError) throw deleteError;\n\n    console.log(`delete-user-refund: successfully deleted user ${userId} (${email})`);\n\n    return new Response(\n      JSON.stringify({ success: true, email, userId }),\n      { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" }, status: 200 }\n    );\n  } catch (error) {\n    console.error(\"delete-user-refund error:\", error);\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
  "generate-carousel": "import { serve } from \"https://deno.land/std@0.168.0/http/server.ts\";\nimport { createClient } from \"https://esm.sh/@supabase/supabase-js@2.49.4\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version\",\n};\n\n// ─── IMAGE PROVIDER TOGGLE ───\n// \"fal\" = fal.ai nano-banana-pro/edit (primary)\n// \"vertex\" = Vertex AI gemini-3-pro-image-preview (standby)\nconst IMAGE_PROVIDER: \"fal\" | \"vertex\" = \"fal\";\n\nfunction base64url(buf: ArrayBuffer): string {\n  const bytes = new Uint8Array(buf);\n  let binary = \"\";\n  for (const b of bytes) binary += String.fromCharCode(b);\n  return btoa(binary).replace(/\\+/g, \"-\").replace(/\\//g, \"_\").replace(/=+$/, \"\");\n}\n\nasync function getAccessToken(saJson: {\n  client_email: string;\n  private_key: string;\n  token_uri: string;\n}): Promise<string> {\n  const now = Math.floor(Date.now() / 1000);\n  const header = base64url(new TextEncoder().encode(JSON.stringify({ alg: \"RS256\", typ: \"JWT\" })));\n  const payload = base64url(\n    new TextEncoder().encode(\n      JSON.stringify({\n        iss: saJson.client_email,\n        sub: saJson.client_email,\n        aud: saJson.token_uri,\n        scope: \"https://www.googleapis.com/auth/cloud-platform\",\n        iat: now,\n        exp: now + 3600,\n      })\n    )\n  );\n\n  const pemBody = saJson.private_key\n    .replace(/-----BEGIN PRIVATE KEY-----/, \"\")\n    .replace(/-----END PRIVATE KEY-----/, \"\")\n    .replace(/\\n/g, \"\");\n  const binaryKey = Uint8Array.from(atob(pemBody), (c) => c.charCodeAt(0));\n  const cryptoKey = await crypto.subtle.importKey(\n    \"pkcs8\",\n    binaryKey,\n    { name: \"RSASSA-PKCS1-v1_5\", hash: \"SHA-256\" },\n    false,\n    [\"sign\"]\n  );\n  const signature = await crypto.subtle.sign(\n    \"RSASSA-PKCS1-v1_5\",\n    cryptoKey,\n    new TextEncoder().encode(`${header}.${payload}`)\n  );\n  const jwt = `${header}.${payload}.${base64url(signature)}`;\n\n  const tokenRes = await fetch(saJson.token_uri, {\n    method: \"POST\",\n    headers: { \"Content-Type\": \"application/x-www-form-urlencoded\" },\n    body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`,\n  });\n  if (!tokenRes.ok) {\n    const errText = await tokenRes.text();\n    throw new Error(`Token exchange failed (${tokenRes.status}): ${errText}`);\n  }\n  const tokenData = await tokenRes.json();\n  return tokenData.access_token;\n}\n\nasync function imageUrlToBase64(url: string): Promise<{ mimeType: string; data: string }> {\n  const res = await fetch(url);\n  if (!res.ok) throw new Error(`Failed to fetch image: ${res.status} ${url}`);\n  const buf = await res.arrayBuffer();\n  const bytes = new Uint8Array(buf);\n  let binary = \"\";\n  for (const b of bytes) binary += String.fromCharCode(b);\n  const base64 = btoa(binary);\n  const contentType = res.headers.get(\"content-type\") || \"image/png\";\n  return { mimeType: contentType.split(\";\")[0], data: base64 };\n}\n\n// ─── FAL.AI INTEGRATION ───\n\nfunction buildFalPrompt(slide: any, product_name: string, creative_style: string, numSlides: number, typographyStyle: string, existingSlideUrls?: string[], useAiImage?: boolean): string {\n  const lines: string[] = [\n    `Crie um slide de carrossel publicitário no formato 1:1 (quadrado).`,\n    `Produto: ${product_name}`,\n    `Estilo visual: ${creative_style || \"clean premium tecnológico\"}`,\n    ``,\n    `--- CONTEÚDO DO SLIDE ---`,\n    `Slide ${slide.slide_number} de ${numSlides} — Função: ${slide.slide_role}`,\n    `Headline: ${slide.headline}`,\n    `Subtexto: ${slide.subtext}`,\n    slide.cta ? `CTA: ${slide.cta}` : \"\",\n    ``,\n    `--- TIPOGRAFIA (OBRIGATÓRIO) ---`,\n    `REGRA PRINCIPAL: TODOS os slides DEVEM usar EXATAMENTE a mesma fonte/estilo tipográfico.`,\n    `Estilo definido: ${typographyStyle}`,\n    `Headlines: sans-serif geométrica bold (estilo Montserrat Bold). MESMA fonte em TODOS os slides.`,\n    `Subtextos: sans-serif regular/light (estilo Montserrat Regular). MESMA fonte em TODOS os slides.`,\n    `CTA: mesma família tipográfica do headline, em bold ou semibold.`,\n    `PROIBIDO: fontes serifadas, manuscritas, cursivas ou decorativas. PROIBIDO variar a font-family entre slides.`,\n    ``,\n    `--- COMPOSIÇÃO ---`,\n    `OBRIGATÓRIO: renderizar os textos (headline, subtexto, cta) diretamente na imagem, em português do Brasil, com tipografia legível e bem posicionada.`,\n    `O headline deve ter destaque visual (maior, bold, contraste alto).`,\n    `O subtexto deve aparecer menor, abaixo do headline.`,\n    slide.cta ? `Renderizar CTA como botão ou destaque visual.` : \"\",\n    `Todos os textos em PORTUGUÊS DO BRASIL exatamente como fornecidos — não traduzir, não alterar.`,\n    `Design clean, premium e profissional.`,\n    `Background elaborado com elementos visuais contextuais.`,\n    `Efeitos tecnológicos: linhas geométricas, gradientes sutis, overlays.`,\n    `PROIBIDO: NÃO incluir numeração de slide (ex: 1/6, 2/8).`,\n    slide.slide_role === \"gancho\" ? \"Visual chamativo e impactante para prender atenção.\" : \"\",\n    slide.slide_role === \"cta\" ? \"Visual de fechamento com destaque para call-to-action.\" : \"\",\n    existingSlideUrls?.length ? \"REFERÊNCIA DE ESTILO: COPIAR EXATAMENTE a mesma tipografia, paleta de cores, elementos decorativos e composição visual dos slides de referência. A fonte deve ser idêntica.\" : \"\",\n    useAiImage ? `GERAÇÃO DE IMAGEM COM IA: crie elementos visuais, ilustrações e cenários que representem o conceito do slide. Contexto: ${product_name}. Função: ${slide.slide_role}.` : \"\",\n  ];\n  return lines.filter(Boolean).join(\"\\n\");\n}\n\nasync function generateSlideWithFal(\n  prompt: string,\n  referenceImageUrls: string[],\n): Promise<string> {\n  const FAL_KEY = Deno.env.get(\"FAL_KEY\");\n  if (!FAL_KEY) throw new Error(\"FAL_KEY not configured\");\n\n  const falInput: any = {\n    prompt,\n    aspect_ratio: \"1:1\",\n  };\n  if (referenceImageUrls.length > 0) {\n    falInput.image_urls = referenceImageUrls;\n  }\n\n  console.log(\"[fal.ai] Calling synchronous endpoint...\");\n\n  // Use synchronous endpoint (fal.run) instead of queue\n  const res = await fetch(\"https://fal.run/fal-ai/nano-banana-pro/edit\", {\n    method: \"POST\",\n    headers: {\n      Authorization: `Key ${FAL_KEY}`,\n      \"Content-Type\": \"application/json\",\n    },\n    body: JSON.stringify(falInput),\n  });\n\n  if (!res.ok) {\n    const errText = await res.text();\n    throw new Error(`fal.ai error (${res.status}): ${errText.substring(0, 500)}`);\n  }\n\n  const resultData = await res.json();\n\n  // Extract image URL from fal.ai response\n  const imageUrl = resultData?.images?.[0]?.url || resultData?.image?.url || resultData?.output?.images?.[0]?.url;\n  if (!imageUrl) {\n    console.error(\"[fal.ai] Unexpected response structure:\", JSON.stringify(resultData).substring(0, 500));\n    throw new Error(\"No image URL in fal.ai response\");\n  }\n\n  console.log(`[fal.ai] Image generated: ${imageUrl.substring(0, 80)}...`);\n  return imageUrl;\n}\n\nasync function downloadAndUploadToStorage(\n  imageUrl: string,\n  supabaseAdmin: any,\n): Promise<string> {\n  const res = await fetch(imageUrl);\n  if (!res.ok) throw new Error(`Failed to download fal.ai image: ${res.status}`);\n\n  const buf = await res.arrayBuffer();\n  const bytes = new Uint8Array(buf);\n  const contentType = res.headers.get(\"content-type\") || \"image/png\";\n  const ext = contentType.includes(\"jpeg\") || contentType.includes(\"jpg\") ? \"jpg\" : \"png\";\n  const fileName = `carousel-${crypto.randomUUID()}.${ext}`;\n\n  const { error } = await supabaseAdmin.storage\n    .from(\"generated-creatives\")\n    .upload(fileName, bytes, { contentType, upsert: false });\n  if (error) throw new Error(`Storage upload failed: ${error.message}`);\n\n  const { data: urlData } = supabaseAdmin.storage.from(\"generated-creatives\").getPublicUrl(fileName);\n  return urlData.publicUrl;\n}\n\n// ─── SYSTEM PROMPT FOR COPY GENERATION ───\nconst CAROUSEL_SYSTEM_PROMPT = `Você é um copywriter especialista em marketing direto, Meta Ads, social media e criação de carrosséis estáticos de alta conversão para produtos físicos, digitais e serviços.\n\nSua tarefa é gerar a copy completa de um carrossel publicitário ou de conteúdo estratégico com base nas informações fornecidas pelo usuário.\n\nO carrossel deve ter entre 4 e 8 slides.\nO último slide deve ser sempre um slide de fechamento com CTA obrigatório.\nCada slide deve cumprir uma função estratégica dentro de uma progressão lógica de persuasão.\n\nSeu objetivo é criar um carrossel com estrutura forte, clareza, impacto visual, progressão narrativa e potencial de conversão.\n\nREGRAS GERAIS:\n1. Escreva sempre em português do Brasil.\n2. Nunca gere textos genéricos, vagos ou superficiais.\n3. Evite excesso de texto por slide. O conteúdo precisa caber visualmente em um carrossel.\n4. Cada slide deve ter copy curta, clara, forte e visualmente escaneável.\n5. O texto deve soar natural, persuasivo e moderno.\n6. Não use parágrafos longos.\n7. Não repita a mesma ideia em slides diferentes.\n8. O último slide deve conter CTA claro e direto.\n9. A estrutura deve ser adaptada conforme a quantidade de slides.\n10. A copy deve refletir o objetivo do carrossel informado pelo usuário.\n11. Sempre considerar dores, benefícios, objeções, promessa e contexto do produto para construir a narrativa.\n12. Quando fizer sentido, usar linguagem de contraste, curiosidade, especificidade, identificação, desejo e urgência.\n13. O texto deve ser pensado para performance em redes sociais e anúncios.\n14. Gere também uma orientação estratégica curta sobre a função de cada slide.\n15. Sempre mantenha coerência entre os slides, como se fosse uma sequência única e intencional.\n16. Priorize headlines curtas e fortes, com no máximo 12 palavras sempre que possível.\n17. Priorize subtextos curtos, com no máximo 18 palavras sempre que possível.\n18. Nunca escreva como se todos os slides fossem iguais em intensidade. Varie o ritmo da narrativa.\n19. Sempre faça o último slide funcionar como fechamento persuasivo e estímulo de ação.\n\nESTRUTURA ESTRATÉGICA:\nVocê deve distribuir os slides dentro desta lógica, adaptando conforme a quantidade escolhida:\n- Slide 1: Gancho forte\n- Slide 2: Dor, problema ou identificação\n- Slide 3: Agravamento, consequência ou aprofundamento\n- Slide 4: Virada, insight ou nova perspectiva\n- Slide 5: Solução ou apresentação da oferta\n- Slide 6: Benefícios principais\n- Slide 7: Quebra de objeção, reforço ou prova lógica\n- Slide final: CTA\n\nADAPTAÇÃO POR QUANTIDADE DE SLIDES:\n- Se forem 4 slides: 1.Gancho 2.Dor 3.Solução 4.CTA\n- Se forem 5 slides: 1.Gancho 2.Dor 3.Insight 4.Solução 5.CTA\n- Se forem 6 slides: 1.Gancho 2.Dor 3.Agravamento 4.Solução 5.Benefícios 6.CTA\n- Se forem 7 slides: 1.Gancho 2.Dor 3.Agravamento 4.Insight 5.Solução 6.Benefícios 7.CTA\n- Se forem 8 slides: 1.Gancho 2.Dor 3.Agravamento 4.Insight 5.Solução 6.Benefícios 7.Quebra de objeção 8.CTA\n\nOBJETIVO DO CARROSSEL:\nAdapte o tom e a estrutura conforme o objetivo informado:\n- vender diretamente\n- gerar curiosidade\n- educar / entregar valor\n- quebrar objeções\n- engajar (salvar, compartilhar, comentar)\n\nDIRETRIZES DE COPY:\n- O slide 1 deve prender atenção imediatamente.\n- O slide final deve estimular ação.\n- Use headlines que funcionem bem visualmente.\n- Quando necessário, inclua subtexto curto.\n- Não torne todos os slides exageradamente chamativos. Varie o ritmo da narrativa.\n- Misture impacto, clareza e fluidez.\n- Benefícios devem ser concretos.\n- Objeções devem ser respondidas com lógica simples e convincente.\n- O CTA final deve ser compatível com o contexto da oferta.\n- O texto precisa caber bem em layout de slide.\n- Evite frases longas demais.\n- Sempre pense em performance para Meta Ads e redes sociais.`;\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") return new Response(null, { headers: corsHeaders });\n\n  try {\n    const authHeader = req.headers.get(\"authorization\");\n    if (!authHeader) throw new Error(\"Missing authorization header\");\n\n    const body = await req.json();\n    const { phase } = body;\n\n    if (phase === \"copy\") {\n      return await handleCopyPhase(body);\n    } else if (phase === \"images\") {\n      return await handleImagesPhase(body);\n    } else if (phase === \"single-image\") {\n      return await handleSingleImagePhase(body);\n    } else {\n      throw new Error(\"Invalid phase. Must be 'copy', 'images', or 'single-image'.\");\n    }\n  } catch (e) {\n    console.error(\"generate-carousel error:\", e);\n    return new Response(\n      JSON.stringify({ error: e instanceof Error ? e.message : \"Unknown error\" }),\n      { status: 500, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n    );\n  }\n});\n\n// ═══════════════════════════════════════════════════════\n// PHASE 1: Generate copy only (fast, ~5s)\n// ═══════════════════════════════════════════════════════\nasync function handleCopyPhase(body: any) {\n  const OPENAI_API_KEY = Deno.env.get(\"OPENAI_API_KEY\");\n  if (!OPENAI_API_KEY) throw new Error(\"OPENAI_API_KEY not configured\");\n\n  const { product_name, main_promise, pain_points, benefits, objections, carousel_objective, creative_style, extra_context, slides_count, cta } = body;\n\n  if (!product_name || !main_promise || !pain_points || !benefits || !carousel_objective)\n    throw new Error(\"Missing required fields\");\n\n  const numSlides = Math.min(Math.max(4, slides_count || 4), 8);\n\n  console.log(\"Phase 1 (copy): Generating carousel copy via OpenAI...\");\n\n  const userPrompt = `Quantidade de slides: ${numSlides}\nNome do produto: ${product_name}\nPromessa principal: ${main_promise}\nPrincipais dores: ${pain_points}\nPrincipais benefícios: ${benefits}\nPrincipais objeções: ${objections || \"Nenhuma informada\"}\nObjetivo do carrossel: ${carousel_objective}\nTom/estilo desejado: ${creative_style || \"Não especificado\"}\nCTA base informado pelo usuário: ${cta || \"A IA deve criar um CTA adequado\"}\nInformações adicionais: ${extra_context || \"Nenhuma\"}\n\nREGRA DE CTA: Use o CTA informado pelo usuário como ponto de partida e reescreva-o para o slide final incluindo uma frase complementar que desperte gatilho de urgência ou gatilho de desejo. Ex: se o CTA base for \"Saiba Mais\", o CTA final pode ser \"Saiba Mais Antes que Acabe\" ou \"Descubra o Segredo — Saiba Mais\". Se o CTA base for \"Compre Agora\", pode virar \"Compre Agora e Garanta o Seu\" ou \"Compre Agora — Oferta por Tempo Limitado\". Mantenha o CTA curto, direto e com no máximo 8 palavras.\n\nREGRA DE LEGENDAS: Além da copy dos slides, gere também 3 opções de legenda para a postagem do carrossel. Cada legenda deve seguir a estrutura: 1) Gancho forte (primeira linha que prende atenção), 2) Desenvolvimento persuasivo (2-3 frases curtas), 3) CTA final. As legendas devem ser variadas em tom e abordagem, baseadas nas informações do produto. Máximo de 280 caracteres por legenda.\n\nAgora gere a copy completa do carrossel.`;\n\n  const slideSchema = {\n    type: \"object\" as const,\n    properties: {\n      slide_number: { type: \"number\" as const },\n      slide_role: { type: \"string\" as const },\n      strategy: { type: \"string\" as const },\n      headline: { type: \"string\" as const },\n      subtext: { type: \"string\" as const },\n      cta: { type: \"string\" as const },\n    },\n    required: [\"slide_number\", \"slide_role\", \"strategy\", \"headline\", \"subtext\", \"cta\"] as const,\n  };\n\n  const copyResponse = await fetch(\"https://api.openai.com/v1/chat/completions\", {\n    method: \"POST\",\n    headers: {\n      Authorization: `Bearer ${OPENAI_API_KEY}`,\n      \"Content-Type\": \"application/json\",\n    },\n    body: JSON.stringify({\n      model: \"gpt-5.4-mini\",\n      messages: [\n        { role: \"system\", content: CAROUSEL_SYSTEM_PROMPT },\n        { role: \"user\", content: userPrompt },\n      ],\n      tools: [\n        {\n          type: \"function\",\n          function: {\n            name: \"generate_carousel\",\n            description: \"Return the complete carousel copy as structured JSON\",\n            parameters: {\n              type: \"object\",\n              properties: {\n                carousel_title: { type: \"string\", description: \"Título estratégico interno do carrossel\" },\n                slides_count: { type: \"number\", description: \"Quantidade de slides\" },\n                credits_cost: { type: \"number\", description: \"Custo em créditos (igual a slides_count)\" },\n                objective: { type: \"string\", description: \"Objetivo do carrossel\" },\n                slides: {\n                  type: \"array\",\n                  description: \"Array de slides do carrossel\",\n                  items: slideSchema,\n                },\n                ad_captions: {\n                  type: \"array\",\n                  description: \"3 opções de legenda para a postagem do carrossel\",\n                  items: {\n                    type: \"object\",\n                    properties: {\n                      caption: { type: \"string\", description: \"Legenda completa pronta para uso\" },\n                    },\n                    required: [\"caption\"],\n                  },\n                },\n              },\n              required: [\"carousel_title\", \"slides_count\", \"credits_cost\", \"objective\", \"slides\", \"ad_captions\"],\n            },\n          },\n        },\n      ],\n      tool_choice: { type: \"function\", function: { name: \"generate_carousel\" } },\n    }),\n  });\n\n  if (!copyResponse.ok) {\n    const t = await copyResponse.text();\n    console.error(\"OpenAI error:\", copyResponse.status, t);\n    if (copyResponse.status === 429) {\n      return new Response(JSON.stringify({ error: \"Rate limit exceeded. Try again shortly.\" }), {\n        status: 429,\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n    throw new Error(`OpenAI error (${copyResponse.status})`);\n  }\n\n  const copyData = await copyResponse.json();\n  const toolCall = copyData.choices?.[0]?.message?.tool_calls?.[0];\n  if (!toolCall) throw new Error(\"No tool call in OpenAI response\");\n\n  const carouselCopy = JSON.parse(toolCall.function.arguments);\n  console.log(\"Copy generated:\", carouselCopy.carousel_title, \"-\", carouselCopy.slides.length, \"slides\");\n\n  return new Response(\n    JSON.stringify({ copy: carouselCopy }),\n    { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n  );\n}\n\n// ═══════════════════════════════════════════════════════\n// PHASE 2: Generate images from approved copy (slow)\n// ═══════════════════════════════════════════════════════\nasync function handleImagesPhase(body: any) {\n  const SUPABASE_URL = Deno.env.get(\"SUPABASE_URL\")!;\n  const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\")!;\n  const supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);\n\n  const { image_urls, copy, product_name, creative_style, slides_count } = body;\n  if (!copy?.slides?.length) throw new Error(\"Missing approved copy data\");\n\n  const numSlides = copy.slides.length;\n  const typographyStyle = body.typography_style || \"sans-serif geométrica (Montserrat ou similar)\";\n\n  console.log(`Phase 2 (images): Generating ${numSlides} slide images via ${IMAGE_PROVIDER}...`);\n\n  if (IMAGE_PROVIDER === \"fal\") {\n    return await handleImagesWithFal(copy, image_urls || [], product_name, creative_style, numSlides, typographyStyle, supabaseAdmin);\n  } else {\n    return await handleImagesWithVertex(body, copy, image_urls, product_name, creative_style, numSlides, supabaseAdmin);\n  }\n}\n\n// ─── FAL.AI batch image generation ───\nasync function handleImagesWithFal(\n  copy: any,\n  imageUrls: string[],\n  productName: string,\n  creativeStyle: string,\n  numSlides: number,\n  typographyStyle: string,\n  supabaseAdmin: any,\n) {\n  const generatedSlides: Array<{ slide_number: number; image_url: string }> = [];\n  const failedSlides: number[] = [];\n\n  for (let i = 0; i < copy.slides.length; i++) {\n    const slide = copy.slides[i];\n    let success = false;\n    let lastError = \"\";\n\n    for (let attempt = 0; attempt < 3; attempt++) {\n      try {\n        if (attempt > 0) {\n          const delay = 5000 * attempt;\n          console.log(`[fal.ai] Retry ${attempt} for slide ${i + 1}, waiting ${delay}ms...`);\n          await new Promise(r => setTimeout(r, delay));\n        }\n\n        const startTime = Date.now();\n        const prompt = buildFalPrompt(slide, productName, creativeStyle, numSlides, typographyStyle);\n        const falImageUrl = await generateSlideWithFal(prompt, imageUrls);\n        const storageUrl = await downloadAndUploadToStorage(falImageUrl, supabaseAdmin);\n\n        generatedSlides.push({ slide_number: slide.slide_number, image_url: storageUrl });\n        success = true;\n        const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);\n        console.log(`[fal.ai] Slide ${i + 1}/${numSlides} generated in ${elapsed}s`);\n\n        // Small delay between slides\n        if (i < copy.slides.length - 1) {\n          await new Promise(r => setTimeout(r, 2000));\n        }\n        break;\n      } catch (e) {\n        lastError = e instanceof Error ? e.message : String(e);\n        console.error(`[fal.ai] Slide ${i + 1} attempt ${attempt + 1} failed:`, lastError);\n      }\n    }\n\n    if (!success) {\n      console.error(`[fal.ai] Slide ${i + 1} failed permanently: ${lastError}`);\n      failedSlides.push(i);\n    }\n  }\n\n  if (generatedSlides.length === 0) {\n    return new Response(\n      JSON.stringify({ error: \"Todas as imagens falharam. Tente novamente em alguns minutos.\", fallback: true }),\n      { status: 200, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n    );\n  }\n\n  const failedCount = copy.slides.length - generatedSlides.length;\n  console.log(`[fal.ai] Generated ${generatedSlides.length}/${numSlides} slides (${failedCount} failed)`);\n\n  return new Response(\n    JSON.stringify({\n      slides: generatedSlides,\n      partial: failedCount > 0,\n      failed_count: failedCount,\n    }),\n    { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n  );\n}\n\n// ─── VERTEX AI batch image generation (standby) ───\nasync function handleImagesWithVertex(\n  body: any,\n  copy: any,\n  image_urls: string[],\n  product_name: string,\n  creative_style: string,\n  numSlides: number,\n  supabaseAdmin: any,\n) {\n  const saJsonRaw = Deno.env.get(\"GOOGLE_SERVICE_ACCOUNT_JSON\");\n  if (!saJsonRaw) throw new Error(\"GOOGLE_SERVICE_ACCOUNT_JSON not configured\");\n  const saJson = JSON.parse(saJsonRaw);\n\n  const accessToken = await getAccessToken(saJson);\n\n  let imagesParts: Array<{ inlineData: { mimeType: string; data: string } }> = [];\n  if (image_urls?.length) {\n    console.log(\"Converting\", image_urls.length, \"reference images to base64...\");\n    imagesParts = await Promise.all(\n      image_urls.map(async (url: string) => {\n        const img = await imageUrlToBase64(url);\n        return { inlineData: { mimeType: img.mimeType, data: img.data } };\n      })\n    );\n  }\n\n  const vertexEndpoint = `https://aiplatform.googleapis.com/v1/projects/${saJson.project_id}/locations/global/publishers/google/models/gemini-3-pro-image-preview:generateContent`;\n\n  const generateSlideImage = async (slide: any, index: number) => {\n    const slidePrompt = JSON.stringify({\n      tipo: \"slide_de_carrossel_publicitario\",\n      formato: \"1:1\",\n      idioma: \"português do Brasil\",\n      produto: product_name,\n      estilo: creative_style || \"clean premium tecnológico\",\n      conteudo_do_slide: {\n        numero: slide.slide_number,\n        funcao: slide.slide_role,\n        texto_headline: slide.headline,\n        texto_subtexto: slide.subtext,\n        texto_cta: slide.cta || null,\n      },\n      tipografia: {\n        regra_principal: \"TODOS os slides do carrossel DEVEM usar EXATAMENTE a mesma fonte/estilo tipográfico. Consistência tipográfica é OBRIGATÓRIA.\",\n        headline: \"sans-serif geométrica bold (estilo Montserrat Bold ou similar). Todas as headlines devem usar a MESMA fonte em TODOS os slides.\",\n        subtexto: \"sans-serif regular/light (estilo Montserrat Regular ou similar). Todos os subtextos devem usar a MESMA fonte em TODOS os slides.\",\n        cta: \"mesma família tipográfica do headline, em bold ou semibold\",\n        proibicoes: [\n          \"PROIBIDO usar fontes serifadas em qualquer slide\",\n          \"PROIBIDO variar o estilo tipográfico entre slides\",\n          \"PROIBIDO usar fontes manuscritas, cursivas ou decorativas\",\n          \"PROIBIDO misturar famílias tipográficas diferentes entre slides\"\n        ]\n      },\n      instrucoes_de_composicao: [\n        \"OBRIGATÓRIO: renderizar os textos fornecidos (headline, subtexto, cta) diretamente na imagem do slide, em português do Brasil, com tipografia legível e bem posicionada\",\n        \"TIPOGRAFIA: usar EXATAMENTE a mesma fonte sans-serif geométrica bold para headlines e sans-serif regular para subtextos em TODOS os slides. NÃO variar a font-family entre slides.\",\n        \"o headline deve ter destaque visual (maior, bold, contraste alto)\",\n        \"o subtexto deve aparecer menor, abaixo do headline\",\n        \"se houver CTA, renderizar como botão ou destaque visual no slide\",\n        \"todos os textos devem estar em PORTUGUÊS DO BRASIL exatamente como fornecidos — não traduzir, não alterar\",\n        \"criar um slide visualmente impactante para carrossel de anúncio\",\n        \"usar as imagens de referência como base visual quando fornecidas\",\n        \"manter design clean, premium e profissional\",\n        \"garantir que o slide funcione bem em sequência com os demais\",\n        \"criar background elaborado com elementos visuais contextuais\",\n      \"incluir efeitos tecnológicos: linhas geométricas, gradientes sutis, overlays\",\n        `este é o slide ${slide.slide_number} de ${numSlides} — função: ${slide.slide_role}`,\n        \"PROIBIDO: NÃO incluir numeração de slide na imagem (ex: 1/6, 2/8, slide 3 de 5, etc). A imagem não deve conter nenhum indicador numérico de posição ou sequência.\",\n        slide.slide_role === \"gancho\" ? \"visual chamativo e impactante para prender atenção\" : \"\",\n        slide.slide_role === \"cta\" ? \"visual de fechamento com destaque para call-to-action\" : \"\",\n      ].filter(Boolean),\n    }, null, 2);\n\n    const vertexPayload = {\n      contents: [{ role: \"user\", parts: [{ text: slidePrompt }, ...imagesParts] }],\n      generationConfig: { responseModalities: [\"IMAGE\"], imageConfig: { aspectRatio: \"1:1\" } },\n    };\n\n    const res = await fetch(vertexEndpoint, {\n      method: \"POST\",\n      headers: { Authorization: `Bearer ${accessToken}`, \"Content-Type\": \"application/json\" },\n      body: JSON.stringify(vertexPayload),\n    });\n\n    if (!res.ok) {\n      const errText = await res.text();\n      throw new Error(`Vertex AI error for slide ${index + 1} (${res.status}): ${errText.substring(0, 500)}`);\n    }\n\n    const result = await res.json();\n    const candidates = result.candidates || [];\n    for (const candidate of candidates) {\n      const parts = candidate.content?.parts || [];\n      for (const part of parts) {\n        if (part.inlineData?.data) {\n          return { base64: part.inlineData.data, mimeType: part.inlineData.mimeType || \"image/png\" };\n        }\n      }\n    }\n    throw new Error(`No image in Vertex AI response for slide ${index + 1}`);\n  };\n\n  const generatedImages: Array<{ base64: string; mimeType: string; index: number } | null> = [];\n  for (let i = 0; i < copy.slides.length; i++) {\n    const slide = copy.slides[i];\n    let lastError: string | null = null;\n    let success = false;\n\n    for (let attempt = 0; attempt < 3; attempt++) {\n      try {\n        if (attempt > 0) {\n          const delay = Math.min(10000 * Math.pow(2, attempt - 1), 60000);\n          console.log(`Retry ${attempt} for slide ${i + 1}, waiting ${delay}ms...`);\n          await new Promise(r => setTimeout(r, delay));\n        }\n        const startTime = Date.now();\n        const img = await generateSlideImage(slide, i);\n        generatedImages.push({ ...img, index: i });\n        success = true;\n        const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);\n        console.log(`Slide ${i + 1}/${copy.slides.length} generated successfully in ${elapsed}s`);\n        if (i < copy.slides.length - 1) {\n          console.log(`Waiting 8s before next slide...`);\n          await new Promise(r => setTimeout(r, 8000));\n        }\n        break;\n      } catch (e) {\n        lastError = e instanceof Error ? e.message : String(e);\n        console.error(`Slide ${i + 1} attempt ${attempt + 1} failed:`, lastError);\n        if (!lastError.includes(\"429\") && !lastError.includes(\"RESOURCE_EXHAUSTED\")) break;\n      }\n    }\n\n    if (!success) {\n      console.error(`Slide ${i + 1} failed permanently: ${lastError}`);\n      generatedImages.push(null);\n    }\n  }\n\n  const successfulImages = generatedImages.filter((img): img is NonNullable<typeof img> => img !== null);\n\n  if (successfulImages.length === 0) {\n    return new Response(\n      JSON.stringify({ error: \"Todas as imagens falharam. Tente novamente em alguns minutos.\", fallback: true }),\n      { status: 200, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n    );\n  }\n\n  console.log(\"Uploading\", successfulImages.length, \"slide images to storage...\");\n  const slideResults = await Promise.all(\n    successfulImages.map(async (img) => {\n      const ext = img.mimeType.includes(\"jpeg\") || img.mimeType.includes(\"jpg\") ? \"jpg\" : \"png\";\n      const fileName = `carousel-${crypto.randomUUID()}.${ext}`;\n      const binaryStr = atob(img.base64);\n      const bytes = new Uint8Array(binaryStr.length);\n      for (let j = 0; j < binaryStr.length; j++) bytes[j] = binaryStr.charCodeAt(j);\n\n      const { error } = await supabaseAdmin.storage\n        .from(\"generated-creatives\")\n        .upload(fileName, bytes, { contentType: img.mimeType, upsert: false });\n      if (error) throw new Error(`Storage upload failed for slide ${img.index + 1}: ${error.message}`);\n\n      const { data: urlData } = supabaseAdmin.storage.from(\"generated-creatives\").getPublicUrl(fileName);\n      return { slide_number: copy.slides[img.index].slide_number, image_url: urlData.publicUrl };\n    })\n  );\n\n  const failedCount = copy.slides.length - successfulImages.length;\n  console.log(`Generated ${slideResults.length}/${copy.slides.length} slide images (${failedCount} failed)`);\n\n  return new Response(\n    JSON.stringify({\n      slides: slideResults,\n      partial: failedCount > 0,\n      failed_count: failedCount,\n    }),\n    { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n  );\n}\n\n// ═══════════════════════════════════════════════════════\n// PHASE 3: Generate a SINGLE slide image (no batch)\n// ═══════════════════════════════════════════════════════\nasync function handleSingleImagePhase(body: any) {\n  const SUPABASE_URL = Deno.env.get(\"SUPABASE_URL\")!;\n  const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\")!;\n  const supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);\n\n  const { slide, image_urls, product_name, creative_style, total_slides, carousel_style_reference, use_ai_image, existing_slide_urls } = body;\n  if (!slide || !slide.headline) throw new Error(\"Missing slide data\");\n\n  const typographyStyle = body.typography_style || \"sans-serif geométrica (Montserrat ou similar)\";\n\n  console.log(`Single-image: Generating slide ${slide.slide_number}/${total_slides || \"?\"} via ${IMAGE_PROVIDER}`);\n\n  if (IMAGE_PROVIDER === \"fal\") {\n    return await handleSingleImageWithFal(body, slide, image_urls, product_name, creative_style, total_slides, existing_slide_urls, use_ai_image, typographyStyle, supabaseAdmin);\n  } else {\n    return await handleSingleImageWithVertex(body, slide, image_urls, product_name, creative_style, total_slides, carousel_style_reference, use_ai_image, existing_slide_urls, typographyStyle, supabaseAdmin);\n  }\n}\n\n// ─── FAL.AI single image generation ───\nasync function handleSingleImageWithFal(\n  body: any,\n  slide: any,\n  imageUrls: string[],\n  productName: string,\n  creativeStyle: string,\n  totalSlides: number,\n  existingSlideUrls: string[],\n  useAiImage: boolean,\n  typographyStyle: string,\n  supabaseAdmin: any,\n) {\n  const allRefUrls = [...(imageUrls || [])];\n  if (existingSlideUrls?.length) {\n    allRefUrls.push(...existingSlideUrls.slice(0, 2));\n  }\n\n  let lastError = \"\";\n  for (let attempt = 0; attempt < 3; attempt++) {\n    try {\n      if (attempt > 0) {\n        const delay = 5000 * attempt;\n        console.log(`[fal.ai] Retry ${attempt} for slide ${slide.slide_number}, waiting ${delay}ms...`);\n        await new Promise(r => setTimeout(r, delay));\n      }\n\n      const startTime = Date.now();\n      const prompt = buildFalPrompt(slide, productName, creativeStyle, totalSlides || 1, typographyStyle, existingSlideUrls, useAiImage);\n      const falImageUrl = await generateSlideWithFal(prompt, allRefUrls);\n      const storageUrl = await downloadAndUploadToStorage(falImageUrl, supabaseAdmin);\n\n      const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);\n      console.log(`[fal.ai] Slide ${slide.slide_number} generated in ${elapsed}s`);\n\n      return new Response(\n        JSON.stringify({ image_url: storageUrl, slide_number: slide.slide_number }),\n        { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n      );\n    } catch (e) {\n      lastError = e instanceof Error ? e.message : String(e);\n      console.error(`[fal.ai] Slide ${slide.slide_number} attempt ${attempt + 1} failed:`, lastError);\n    }\n  }\n\n  return new Response(\n    JSON.stringify({\n      error: `Falha ao gerar slide ${slide.slide_number}: ${lastError}`,\n      fallback: false,\n    }),\n    { status: 200, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n  );\n}\n\n// ─── VERTEX AI single image generation (standby) ───\nasync function handleSingleImageWithVertex(\n  body: any,\n  slide: any,\n  image_urls: string[],\n  product_name: string,\n  creative_style: string,\n  total_slides: number,\n  carousel_style_reference: string,\n  use_ai_image: boolean,\n  existing_slide_urls: string[],\n  typographyStyle: string,\n  supabaseAdmin: any,\n) {\n  const saJsonRaw = Deno.env.get(\"GOOGLE_SERVICE_ACCOUNT_JSON\");\n  if (!saJsonRaw) throw new Error(\"GOOGLE_SERVICE_ACCOUNT_JSON not configured\");\n  const saJson = JSON.parse(saJsonRaw);\n\n  const accessToken = await getAccessToken(saJson);\n\n  let imagesParts: Array<{ inlineData: { mimeType: string; data: string } }> = [];\n  const allRefUrls = [...(image_urls || [])];\n  if (existing_slide_urls?.length) {\n    const styleRefs = existing_slide_urls.slice(0, 2);\n    allRefUrls.push(...styleRefs);\n    console.log(\"Including\", styleRefs.length, \"existing slide(s) as style reference\");\n  }\n  if (allRefUrls.length) {\n    console.log(\"Converting\", allRefUrls.length, \"reference images to base64...\");\n    imagesParts = await Promise.all(\n      allRefUrls.map(async (url: string) => {\n        const img = await imageUrlToBase64(url);\n        return { inlineData: { mimeType: img.mimeType, data: img.data } };\n      })\n    );\n  }\n\n  const vertexEndpoint = `https://aiplatform.googleapis.com/v1/projects/${saJson.project_id}/locations/global/publishers/google/models/gemini-3-pro-image-preview:generateContent`;\n  const styleRef = carousel_style_reference || creative_style || \"clean premium tecnológico\";\n\n  const slidePrompt = JSON.stringify({\n    tipo: \"slide_de_carrossel_publicitario\",\n    formato: \"1:1\",\n    idioma: \"português do Brasil\",\n    produto: product_name,\n    estilo_global_do_carrossel: {\n      estilo: styleRef,\n      instrucao: \"Este slide faz parte de um carrossel. Mantenha a mesma paleta de cores, estilo de fundo, tipografia visual e elementos decorativos consistentes com os demais slides do carrossel.\",\n      total_slides: total_slides || 1,\n    },\n    conteudo_do_slide: {\n      numero: slide.slide_number,\n      funcao: slide.slide_role,\n      texto_headline: slide.headline,\n      texto_subtexto: slide.subtext,\n      texto_cta: slide.cta || null,\n    },\n    tipografia: {\n      regra_principal: \"TODOS os slides do carrossel DEVEM usar EXATAMENTE a mesma fonte/estilo tipográfico. Consistência tipográfica é OBRIGATÓRIA.\",\n      estilo_definido: typographyStyle,\n      headline: \"sans-serif geométrica bold (estilo Montserrat Bold ou similar). Todas as headlines devem usar a MESMA fonte em TODOS os slides.\",\n      subtexto: \"sans-serif regular/light (estilo Montserrat Regular ou similar). Todos os subtextos devem usar a MESMA fonte em TODOS os slides.\",\n      cta: \"mesma família tipográfica do headline, em bold ou semibold\",\n      proibicoes: [\n        \"PROIBIDO usar fontes serifadas em qualquer slide\",\n        \"PROIBIDO variar o estilo tipográfico entre slides\",\n        \"PROIBIDO usar fontes manuscritas, cursivas ou decorativas\",\n        \"PROIBIDO misturar famílias tipográficas diferentes entre slides\"\n      ]\n    },\n    instrucoes_de_composicao: [\n      \"OBRIGATÓRIO: renderizar os textos fornecidos (headline, subtexto, cta) diretamente na imagem do slide, em português do Brasil, com tipografia legível e bem posicionada\",\n      \"TIPOGRAFIA: usar EXATAMENTE a mesma fonte sans-serif geométrica bold para headlines e sans-serif regular para subtextos em TODOS os slides. NÃO variar a font-family entre slides.\",\n      \"o headline deve ter destaque visual (maior, bold, contraste alto)\",\n      \"o subtexto deve aparecer menor, abaixo do headline\",\n      \"se houver CTA, renderizar como botão ou destaque visual no slide\",\n      \"todos os textos devem estar em PORTUGUÊS DO BRASIL exatamente como fornecidos — não traduzir, não alterar\",\n      \"criar um slide visualmente impactante para carrossel de anúncio\",\n      \"usar as imagens de referência como base visual quando fornecidas\",\n      \"manter design clean, premium e profissional\",\n      \"garantir que o slide funcione bem em sequência com os demais\",\n      \"criar background elaborado com elementos visuais contextuais\",\n      \"incluir efeitos tecnológicos: linhas geométricas, gradientes sutis, overlays\",\n      `este é o slide ${slide.slide_number} de ${total_slides || \"?\"} — função: ${slide.slide_role}`,\n      \"PROIBIDO: NÃO incluir numeração de slide na imagem (ex: 1/6, 2/8, slide 3 de 5, etc). A imagem não deve conter nenhum indicador numérico de posição ou sequência.\",\n      \"IMPORTANTE: manter consistência visual com os outros slides do carrossel (mesma paleta, mesmo estilo de fundo, mesmos elementos decorativos)\",\n      existing_slide_urls?.length ? \"REFERÊNCIA DE ESTILO: as imagens de referência incluem slides já gerados deste carrossel. COPIAR EXATAMENTE a mesma tipografia (font-family, peso, tamanho relativo), paleta de cores, elementos decorativos e composição visual. A fonte deve ser idêntica.\" : \"\",\n      slide.slide_role === \"gancho\" ? \"visual chamativo e impactante para prender atenção\" : \"\",\n      slide.slide_role === \"cta\" ? \"visual de fechamento com destaque para call-to-action\" : \"\",\n      use_ai_image ? `GERAÇÃO DE IMAGEM COM IA: crie elementos visuais, ilustrações e cenários que representem o conceito do slide. Contexto do produto: ${product_name}. Função do slide: ${slide.slide_role}. Use criatividade para gerar visuais que complementem os textos e reforcem a mensagem.` : \"\",\n    ].filter(Boolean),\n  }, null, 2);\n\n  const vertexPayload = {\n    contents: [{ role: \"user\", parts: [{ text: slidePrompt }, ...imagesParts] }],\n    generationConfig: { responseModalities: [\"IMAGE\"], imageConfig: { aspectRatio: \"1:1\" } },\n  };\n\n  let lastError: string | null = null;\n  for (let attempt = 0; attempt < 3; attempt++) {\n    try {\n      if (attempt > 0) {\n        const delay = Math.min(10000 * Math.pow(2, attempt - 1), 60000);\n        console.log(`Retry ${attempt} for slide ${slide.slide_number}, waiting ${delay}ms...`);\n        await new Promise(r => setTimeout(r, delay));\n      }\n\n      const startTime = Date.now();\n      const res = await fetch(vertexEndpoint, {\n        method: \"POST\",\n        headers: { Authorization: `Bearer ${accessToken}`, \"Content-Type\": \"application/json\" },\n        body: JSON.stringify(vertexPayload),\n      });\n\n      if (!res.ok) {\n        const errText = await res.text();\n        throw new Error(`Vertex AI error (${res.status}): ${errText.substring(0, 500)}`);\n      }\n\n      const result = await res.json();\n      let imageData: { base64: string; mimeType: string } | null = null;\n      for (const candidate of (result.candidates || [])) {\n        for (const part of (candidate.content?.parts || [])) {\n          if (part.inlineData?.data) {\n            imageData = { base64: part.inlineData.data, mimeType: part.inlineData.mimeType || \"image/png\" };\n            break;\n          }\n        }\n        if (imageData) break;\n      }\n\n      if (!imageData) throw new Error(\"No image in Vertex AI response\");\n\n      const ext = imageData.mimeType.includes(\"jpeg\") || imageData.mimeType.includes(\"jpg\") ? \"jpg\" : \"png\";\n      const fileName = `carousel-${crypto.randomUUID()}.${ext}`;\n      const binaryStr = atob(imageData.base64);\n      const bytes = new Uint8Array(binaryStr.length);\n      for (let j = 0; j < binaryStr.length; j++) bytes[j] = binaryStr.charCodeAt(j);\n\n      const { error: uploadErr } = await supabaseAdmin.storage\n        .from(\"generated-creatives\")\n        .upload(fileName, bytes, { contentType: imageData.mimeType, upsert: false });\n      if (uploadErr) throw new Error(`Storage upload failed: ${uploadErr.message}`);\n\n      const { data: urlData } = supabaseAdmin.storage.from(\"generated-creatives\").getPublicUrl(fileName);\n      const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);\n      console.log(`Slide ${slide.slide_number} generated and uploaded in ${elapsed}s`);\n\n      return new Response(\n        JSON.stringify({ image_url: urlData.publicUrl, slide_number: slide.slide_number }),\n        { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n      );\n    } catch (e) {\n      lastError = e instanceof Error ? e.message : String(e);\n      console.error(`Slide ${slide.slide_number} attempt ${attempt + 1} failed:`, lastError);\n      if (!lastError.includes(\"429\") && !lastError.includes(\"RESOURCE_EXHAUSTED\")) break;\n    }\n  }\n\n  const isQuotaError = lastError!.includes(\"429\") || lastError!.includes(\"RESOURCE_EXHAUSTED\");\n  return new Response(\n    JSON.stringify({\n      error: isQuotaError\n        ? \"Limite de requisições atingido. Aguarde alguns minutos e tente novamente.\"\n        : `Falha ao gerar slide ${slide.slide_number}: ${lastError}`,\n      fallback: isQuotaError,\n      quota_exhausted: isQuotaError,\n    }),\n    { status: 200, headers: { ...corsHeaders, \"Content-Type\": \"application/json\" } }\n  );\n}\n",
  "generate-copy": "import { serve } from \"https://deno.land/std@0.168.0/http/server.ts\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\": \"authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version\",\n};\n\nconst AI_GATEWAY_URL = \"https://ai.gateway.lovable.dev/v1/chat/completions\";\n\nconst systemPrompt = `Você é um copywriter de elite, especialista em criativos estáticos de alta conversão para Meta Ads (Facebook e Instagram). Você gera copies em português do Brasil.\n\nREGRAS OBRIGATÓRIAS:\n- Headline com gancho forte e impactante\n- Linguagem clara, persuasiva e direta — nada genérico\n- Foco total em conversão\n- CTA coerente com o que o usuário informou\n- Textos curtos — pense em criativo estático de anúncio, não em artigo\n- Subheadline é opcional — use apenas quando agregar valor\n- Todas as copies em português do Brasil\n\nDISTRIBUIÇÃO ESTRATÉGICA DOS 3 ÂNGULOS:\n- Ângulo 1: Explorar a DOR PRINCIPAL do público\n- Ângulo 2: Explorar o BENEFÍCIO / TRANSFORMAÇÃO\n- Ângulo 3: Quebrar OBJEÇÃO / mostrar PRATICIDADE / RAPIDEZ / PROVA IMPLÍCITA\n\nCada ângulo deve ser genuinamente diferente dos outros em abordagem e tom.\n\nOPÇÕES VISUAIS POR ÂNGULO:\nPara cada ângulo, gere 2 VARIAÇÕES de conceito visual clean premium para o criativo estático:\n- Variação A1: layout clean e premium — design sofisticado, minimalista e elegante, com composição equilibrada e uso refinado de espaço negativo\n- Variação A2: layout clean e premium — igualmente sofisticado, porém com mais elementos gráficos, texturas e destaques visuais que enriquecem a composição mantendo a elegância\n\nAmbas as variações devem manter o padrão premium e sofisticado. A diferença está na abordagem visual (mais minimalista vs mais rica em elementos), NÃO no tom da copy.\n\nREGRA IMPORTANTE PARA AMBAS AS VARIAÇÕES:\n- Identifique o produto, nicho e suas características\n- Inclua elementos visuais temáticos (ícones, figurinhas, badges, selos) que estejam alinhados com o produto e nicho do anúncio\n- Esses elementos devem reforçar a identidade do nicho e tornar o criativo mais contextualizado e profissional\n- Exemplos: nicho fitness → ícones de halteres, chamas, troféus; nicho beleza → elementos florais, brilhos; nicho educação → livros, lâmpadas, estrelas\n\nCada opção visual deve conter orientações de:\n- Descrição curta da linha visual\n- Distribuição sugerida dos elementos no criativo\n- Orientação de composição\n- Proposta de hierarquia visual\n- Estilo do layout\n- Como destacar o CTA visualmente\n- Elementos temáticos sugeridos (ícones/figurinhas alinhados ao nicho)`;\n\nconst tools = [\n  {\n    type: \"function\",\n    function: {\n      name: \"generate_copies\",\n      description: \"Return 3 ad copy angles, each with 2 visual concept options\",\n      parameters: {\n        type: \"object\",\n        properties: {\n          angles: {\n            type: \"array\",\n            description: \"3 different copy angles\",\n            items: {\n              type: \"object\",\n              properties: {\n                angle_name: { type: \"string\", description: \"Nome do ângulo (ex: Dor Principal, Transformação, Quebra de Objeção)\" },\n                headline: { type: \"string\", description: \"Gancho forte e impactante\" },\n                subheadline: { type: \"string\", description: \"Complemento opcional da headline\" },\n                body: { type: \"string\", description: \"Corpo curto e persuasivo\" },\n                cta: { type: \"string\", description: \"Chamada para ação\" },\n                visual_options: {\n                  type: \"array\",\n                  description: \"2 opções de conceito visual para este ângulo\",\n                  items: {\n                    type: \"object\",\n                    properties: {\n                      option_label: { type: \"string\", description: \"Ex: Variação A1 - Minimalista Premium ou Variação A2 - Premium Rico em Elementos\" },\n                      visual_description: { type: \"string\", description: \"Mini descrição da linha visual\" },\n                      element_distribution: { type: \"string\", description: \"Distribuição sugerida dos elementos no criativo\" },\n                      composition: { type: \"string\", description: \"Orientação de composição\" },\n                      visual_hierarchy: { type: \"string\", description: \"Proposta de hierarquia visual\" },\n                      layout_style: { type: \"string\", description: \"Estilo do layout\" },\n                      cta_highlight: { type: \"string\", description: \"Como destacar o CTA visualmente\" },\n                      thematic_elements: { type: \"string\", description: \"Ícones, figurinhas, badges ou selos temáticos alinhados ao produto e nicho\" },\n                    },\n                    required: [\"option_label\", \"visual_description\", \"element_distribution\", \"composition\", \"visual_hierarchy\", \"layout_style\", \"cta_highlight\", \"thematic_elements\"],\n                  },\n                },\n              },\n              required: [\"angle_name\", \"headline\", \"body\", \"cta\", \"visual_options\"],\n            },\n          },\n          ad_captions: {\n            type: \"array\",\n            description: \"3 opções de legenda para o anúncio/postagem, cada uma com gancho, desenvolvimento e CTA\",\n            items: {\n              type: \"object\",\n              properties: {\n                caption: { type: \"string\", description: \"Legenda completa pronta para uso\" },\n              },\n              required: [\"caption\"],\n            },\n          },\n        },\n        required: [\"angles\", \"ad_captions\"],\n      },\n    },\n  },\n];\n\nasync function callAI(model: string, userPrompt: string, timeoutMs: number) {\n  const LOVABLE_API_KEY = Deno.env.get(\"LOVABLE_API_KEY\");\n  if (!LOVABLE_API_KEY) throw new Error(\"LOVABLE_API_KEY not configured\");\n\n  const controller = new AbortController();\n  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);\n\n  try {\n    const response = await fetch(AI_GATEWAY_URL, {\n      method: \"POST\",\n      headers: {\n        Authorization: `Bearer ${LOVABLE_API_KEY}`,\n        \"Content-Type\": \"application/json\",\n      },\n      body: JSON.stringify({\n        model,\n        messages: [\n          { role: \"system\", content: systemPrompt },\n          { role: \"user\", content: userPrompt },\n        ],\n        tools,\n        tool_choice: { type: \"function\", function: { name: \"generate_copies\" } },\n      }),\n      signal: controller.signal,\n    });\n\n    clearTimeout(timeoutId);\n\n    if (!response.ok) {\n      const t = await response.text();\n      console.error(`AI error (${model}):`, response.status, t);\n      if (response.status === 429) {\n        return { error: \"Rate limit exceeded. Try again shortly.\", status: 429 };\n      }\n      if (response.status === 402) {\n        return { error: \"Credits exhausted.\", status: 402 };\n      }\n      throw new Error(`AI gateway error (${response.status})`);\n    }\n\n    const data = await response.json();\n    const toolCall = data.choices?.[0]?.message?.tool_calls?.[0];\n    if (!toolCall) throw new Error(\"No tool call in response\");\n\n    return { result: JSON.parse(toolCall.function.arguments) };\n  } catch (e) {\n    clearTimeout(timeoutId);\n    if (e.name === \"AbortError\") {\n      console.warn(`Timeout after ${timeoutMs}ms with model ${model}`);\n      throw new Error(\"TIMEOUT\");\n    }\n    throw e;\n  }\n}\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") return new Response(null, { headers: corsHeaders });\n\n  try {\n    const { product_name, promise, pains, benefits, objections, cta } = await req.json();\n\n    const userPrompt = `Gere 3 ângulos de copy com 2 opções visuais cada para o seguinte produto:\n\nProduto: ${product_name}\nPromessa: ${promise}\nDores: ${pains}\nBenefícios: ${benefits}\nObjeções: ${objections || \"Nenhuma informada\"}\nCTA base informado pelo usuário: ${cta || \"Compre agora\"}\n\nREGRA DE CTA: Use o CTA informado pelo usuário como ponto de partida e reescreva-o incluindo uma frase que desperte gatilho de urgência ou curiosidade. Ex: se o CTA base for \"Saiba Mais\", o CTA final pode ser \"Saiba Mais Antes que Acabe\" ou \"Descubra o Segredo — Saiba Mais\".\n\nREGRA DE LEGENDAS: Além dos ângulos, gere também 3 opções de legenda para o anúncio/postagem. Cada legenda deve seguir a estrutura: 1) Gancho forte (primeira linha que prende atenção), 2) Desenvolvimento persuasivo (2-3 frases curtas), 3) CTA final. As legendas devem ser variadas em tom e abordagem, baseadas nas informações do produto. Máximo de 280 caracteres por legenda.`;\n\n    // Try primary model with 90s timeout\n    let response;\n    try {\n      console.log(\"Attempting with openai/gpt-5-mini...\");\n      response = await callAI(\"openai/gpt-5-mini\", userPrompt, 90000);\n    } catch (e) {\n      if (e.message === \"TIMEOUT\") {\n        // Fallback to faster model\n        console.log(\"Primary model timed out, retrying with google/gemini-2.5-flash...\");\n        response = await callAI(\"google/gemini-2.5-flash\", userPrompt, 120000);\n      } else {\n        throw e;\n      }\n    }\n\n    // Handle rate limit / credits errors\n    if (response.error) {\n      return new Response(JSON.stringify({ error: response.error }), {\n        status: response.status,\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      });\n    }\n\n    return new Response(JSON.stringify(response.result), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n    });\n  } catch (e) {\n    console.error(\"generate-copy error:\", e);\n    return new Response(JSON.stringify({ error: e instanceof Error ? e.message : \"Unknown error\" }), {\n      status: 500,\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n    });\n  }\n});\n",
  "generate-creative": "import { serve } from \"https://deno.land/std@0.168.0/http/server.ts\";\nimport { createClient } from \"https://esm.sh/@supabase/supabase-js@2.49.4\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version\",\n};\n\nconst FORMAT_TO_RATIO: Record<string, string> = {\n  \"1:1\": \"1:1\",\n  \"4:5\": \"4:5\",\n  \"9:16\": \"9:16\",\n  \"16:9\": \"16:9\",\n};\n\nfunction buildPrompt(data: {\n  product_name: string;\n  format: string;\n  promise: string;\n  pains: string;\n  benefits: string;\n  objections?: string;\n  headline: string;\n  body: string;\n  cta: string;\n  color_palette?: string[];\n  additional_instructions?: string;\n  visual_option: {\n    visual_description: string;\n    element_distribution: string;\n    composition: string;\n    visual_hierarchy: string;\n    layout_style: string;\n    cta_highlight: string;\n    thematic_elements?: string;\n  };\n}): string {\n  const benefitsList = data.benefits\n    .split(/\\r?\\n|,|;/)\n    .map((item) => item.trim())\n    .filter(Boolean);\n\n  const painList = data.pains\n    .split(/\\r?\\n|,|;/)\n    .map((item) => item.trim())\n    .filter(Boolean);\n\n  const objectionsList = (data.objections || \"\")\n    .split(/\\r?\\n|,|;/)\n    .map((item) => item.trim())\n    .filter(Boolean);\n\n  return JSON.stringify(\n    {\n      tipo: \"criativo_publicitario_estatico\",\n      formato: data.format,\n      idioma_textos: \"português do Brasil\",\n      objetivo: \"anuncio_meta_ads\",\n      produto: {\n        nome: data.product_name,\n        promessa: data.promise,\n      },\n      conceito_criativo: {\n        angulo: data.headline,\n        dor_principal: painList,\n        beneficios: benefitsList,\n        objecoes_trabalhadas: objectionsList,\n      },\n      imagens_referencia: {\n        instrucao:\n          \"usar as imagens fornecidas como base principal da composição, preservando identidade visual e contexto do produto/oferta\",\n      },\n      layout: {\n        estilo: data.visual_option.layout_style,\n        composicao: data.visual_option.composition,\n        hierarquia_visual: data.visual_option.visual_hierarchy,\n        distribuicao_elementos: data.visual_option.element_distribution,\n        destaque_cta: data.visual_option.cta_highlight,\n      },\n      textos: {\n        headline: data.headline,\n        subheadline: data.body,\n        cta: data.cta,\n      },\n      direcao_visual: {\n        descricao: data.visual_option.visual_description,\n        atmosfera:\n          \"clean premium, conversão alta, estética realista de anúncio para Instagram/Facebook\",\n      },\n      instrucoes_extras: [\n        \"manter design clean, premium e informativo\",\n        \"garantir legibilidade em telas mobile\",\n        \"priorizar contraste forte entre elementos principais e fundo\",\n        \"usar as imagens de referência como elementos centrais da composição\",\n        \"não adicionar texto renderizado na imagem; apenas compor o visual\",\n        \"evitar poluição visual e manter acabamento profissional\",\n        \"criar background elaborado com elementos visuais que façam referência ao produto e nicho, evitar fundos de cor única — usar texturas, gradientes, padrões ou elementos contextuais\",\n        \"incluir efeitos tecnológicos como linhas geométricas finas, gradientes sutis, elementos em transparência, overlays e formas abstratas que deem um visual moderno e tecnológico ao criativo\",\n        ...(data.color_palette && data.color_palette.length > 0\n          ? [\n              `utilizar a seguinte paleta de cores como base do design: ${data.color_palette.join(\", \")}`,\n            ]\n          : []),\n        data.visual_option.thematic_elements\n          ? `incluir elementos visuais temáticos alinhados ao nicho: ${data.visual_option.thematic_elements}`\n          : \"incluir ícones ou elementos visuais que reforcem a identidade do nicho do produto\",\n        ...(data.additional_instructions\n          ? [\n              `orientações adicionais do usuário: ${data.additional_instructions}`,\n            ]\n          : []),\n      ],\n    },\n    null,\n    2,\n  );\n}\n\nasync function generateWithRetry(\n  falKey: string,\n  prompt: string,\n  imageUrls: string[],\n  aspectRatio: string,\n  index: number,\n  maxRetries = 3,\n): Promise<{ url: string }> {\n  for (let attempt = 0; attempt <= maxRetries; attempt++) {\n    const res = await fetch(\"https://fal.run/fal-ai/nano-banana-pro/edit\", {\n      method: \"POST\",\n      headers: {\n        Authorization: `Key ${falKey}`,\n        \"Content-Type\": \"application/json\",\n      },\n      body: JSON.stringify({\n        prompt,\n        image_urls: imageUrls,\n        aspect_ratio: aspectRatio,\n      }),\n    });\n\n    if (res.status === 429) {\n      if (attempt === maxRetries) {\n        throw new Error(\"Limite de requisições atingido. Tente novamente em alguns minutos.\");\n      }\n      const wait = Math.pow(2, attempt + 1) * 1000;\n      console.log(`Rate limited (429) on image ${index}, waiting ${wait}ms...`);\n      await new Promise((r) => setTimeout(r, wait));\n      continue;\n    }\n\n    if (!res.ok) {\n      const errText = await res.text();\n      throw new Error(`fal.ai error (${res.status}): ${errText.substring(0, 500)}`);\n    }\n\n    const result = await res.json();\n    const generatedUrl = result?.images?.[0]?.url;\n    if (!generatedUrl) {\n      throw new Error(`No image in fal.ai response for index ${index}: ${JSON.stringify(result).substring(0, 500)}`);\n    }\n\n    return { url: generatedUrl };\n  }\n  throw new Error(\"Max retries exceeded\");\n}\n\nasync function updateRequestStatus(\n  supabaseAdmin: ReturnType<typeof createClient>,\n  userId: string,\n  productName: string,\n  status: string,\n) {\n  try {\n    const { data } = await supabaseAdmin\n      .from(\"creative_requests\")\n      .select(\"id\")\n      .eq(\"user_id\", userId)\n      .eq(\"product_name\", productName)\n      .eq(\"status\", \"processing\")\n      .order(\"created_at\", { ascending: false })\n      .limit(1)\n      .single();\n\n    if (data?.id) {\n      await supabaseAdmin\n        .from(\"creative_requests\")\n        .update({ status })\n        .eq(\"id\", data.id);\n      console.log(`Updated request ${data.id} status to '${status}'`);\n    }\n  } catch (e) {\n    console.error(\"Failed to update request status:\", e);\n  }\n}\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\")\n    return new Response(null, { headers: corsHeaders });\n\n  try {\n    const falKey = Deno.env.get(\"FAL_KEY\");\n    if (!falKey) throw new Error(\"FAL_KEY not configured\");\n\n    const SUPABASE_URL = Deno.env.get(\"SUPABASE_URL\")!;\n    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\")!;\n    const supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);\n\n    const authHeader = req.headers.get(\"authorization\");\n    if (!authHeader) throw new Error(\"Missing authorization header\");\n\n    const {\n      image_urls,\n      product_name,\n      promise,\n      pains,\n      benefits,\n      objections,\n      headline,\n      body,\n      cta,\n      visual_option,\n      format,\n      quantity,\n      color_palette,\n      additional_instructions,\n    } = await req.json();\n\n    if (!image_urls?.length) throw new Error(\"At least one image is required\");\n    if (!product_name || !headline || !cta || !visual_option)\n      throw new Error(\"Missing required fields\");\n\n    // Extract user_id from JWT for status updates\n    let userId: string | null = null;\n    try {\n      const token = authHeader.replace(\"Bearer \", \"\");\n      const { data: { user } } = await supabaseAdmin.auth.getUser(token);\n      userId = user?.id || null;\n    } catch { /* ignore */ }\n\n    const numImages = Math.min(Math.max(1, quantity || 1), 4);\n    const aspectRatio = FORMAT_TO_RATIO[format] || \"1:1\";\n\n    const promptJson = buildPrompt({\n      product_name,\n      format,\n      promise,\n      pains,\n      benefits,\n      objections,\n      headline,\n      body,\n      cta,\n      color_palette,\n      additional_instructions,\n      visual_option,\n    });\n\n    const prompt = promptJson;\n\n    console.log(\"Generating\", numImages, \"images via fal.ai nano-banana-pro...\");\n    const generatedImages: { url: string }[] = [];\n    for (let i = 0; i < numImages; i++) {\n      console.log(`Generating image ${i + 1}/${numImages}...`);\n      const img = await generateWithRetry(falKey, prompt, image_urls, aspectRatio, i);\n      generatedImages.push(img);\n    }\n\n    console.log(\"Uploading\", generatedImages.length, \"images to storage...\");\n\n    const uploadedUrls = await Promise.all(\n      generatedImages.map(async (img) => {\n        const imgRes = await fetch(img.url);\n        if (!imgRes.ok) throw new Error(`Failed to download generated image: ${imgRes.status}`);\n        const arrayBuf = await imgRes.arrayBuffer();\n        const bytes = new Uint8Array(arrayBuf);\n\n        const contentType = imgRes.headers.get(\"content-type\") || \"image/png\";\n        const ext = contentType.includes(\"jpeg\") || contentType.includes(\"jpg\") ? \"jpg\" : \"png\";\n        const fileName = `${crypto.randomUUID()}.${ext}`;\n\n        const { error } = await supabaseAdmin.storage\n          .from(\"generated-creatives\")\n          .upload(fileName, bytes, {\n            contentType,\n            upsert: false,\n          });\n\n        if (error) throw new Error(`Storage upload failed: ${error.message}`);\n\n        const { data: urlData } = supabaseAdmin.storage\n          .from(\"generated-creatives\")\n          .getPublicUrl(fileName);\n\n        return { url: urlData.publicUrl };\n      })\n    );\n\n    console.log(\"Successfully generated and uploaded\", uploadedUrls.length, \"images\");\n\n    return new Response(JSON.stringify({ images: uploadedUrls }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n    });\n  } catch (e) {\n    console.error(\"generate-creative error:\", e);\n\n    // Try to update request status to 'error'\n    try {\n      const SUPABASE_URL = Deno.env.get(\"SUPABASE_URL\")!;\n      const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\")!;\n      const supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);\n\n      // Find the most recent processing request and mark it as error\n      const { data: processingRequests } = await supabaseAdmin\n        .from(\"creative_requests\")\n        .select(\"id\")\n        .eq(\"status\", \"processing\")\n        .order(\"created_at\", { ascending: false })\n        .limit(5);\n\n      if (processingRequests?.length) {\n        for (const req of processingRequests) {\n          await supabaseAdmin\n            .from(\"creative_requests\")\n            .update({ status: \"error\" })\n            .eq(\"id\", req.id);\n        }\n        console.log(`Marked ${processingRequests.length} processing requests as error`);\n      }\n    } catch (statusErr) {\n      console.error(\"Failed to update request status to error:\", statusErr);\n    }\n\n    return new Response(\n      JSON.stringify({\n        error: e instanceof Error ? e.message : \"Unknown error\",\n      }),\n      {\n        status: 500,\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      }\n    );\n  }\n});\n",
  "handle-payment-success": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport Stripe from \"https://esm.sh/stripe@18.5.0\";\nimport { createClient } from \"npm:@supabase/supabase-js@2.57.2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version\",\n};\n\nconst CREDITS_MAP: Record<string, number> = {\n  \"PACOTE BASICO\": 20,\n  \"PACOTE PRO\": 50,\n  \"PACOTE PLUS\": 100,\n};\n\nfunction generateTempPassword(): string {\n  const chars = \"ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789\";\n  let password = \"\";\n  for (let i = 0; i < 12; i++) {\n    password += chars.charAt(Math.floor(Math.random() * chars.length));\n  }\n  return password;\n}\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  const supabaseAdmin = createClient(\n    Deno.env.get(\"SUPABASE_URL\") ?? \"\",\n    Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\") ?? \"\"\n  );\n\n  try {\n    const { sessionId, packageId } = await req.json();\n    if (!sessionId || !packageId) throw new Error(\"Dados inválidos\");\n\n    const credits = CREDITS_MAP[packageId];\n    if (!credits) throw new Error(\"Pacote inválido\");\n\n    // Verify Stripe session\n    const stripe = new Stripe(Deno.env.get(\"STRIPE_SECRET_KEY\") || \"\", {\n      apiVersion: \"2025-08-27.basil\",\n    });\n\n    const session = await stripe.checkout.sessions.retrieve(sessionId);\n    if (session.payment_status !== \"paid\") {\n      throw new Error(\"Pagamento não confirmado\");\n    }\n\n    const email = session.customer_details?.email;\n    if (!email) throw new Error(\"Email não encontrado na sessão\");\n\n    // Check if user already exists\n    const { data: existingUsers } = await supabaseAdmin.auth.admin.listUsers();\n    const existingUser = existingUsers?.users?.find(u => u.email === email);\n\n    let userId: string;\n    let tempPassword: string | null = null;\n    let isNewUser = false;\n\n    if (existingUser) {\n      userId = existingUser.id;\n\n      // Add credits to existing user\n      const { data: currentCredits } = await supabaseAdmin\n        .from(\"user_credits\")\n        .select(\"credits_balance\")\n        .eq(\"user_id\", userId)\n        .single();\n\n      if (currentCredits) {\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .update({ credits_balance: currentCredits.credits_balance + credits })\n          .eq(\"user_id\", userId);\n      }\n    } else {\n      // Create new user with temp password\n      isNewUser = true;\n      tempPassword = generateTempPassword();\n\n      const { data: newUser, error: createError } = await supabaseAdmin.auth.admin.createUser({\n        email,\n        password: tempPassword,\n        email_confirm: true,\n        user_metadata: { name: email.split(\"@\")[0], must_change_password: true },\n      });\n\n      if (createError || !newUser.user) {\n        throw new Error(\"Erro ao criar conta: \" + (createError?.message || \"desconhecido\"));\n      }\n\n      userId = newUser.user.id;\n\n      // Wait a moment for triggers to create profile and credits\n      await new Promise(resolve => setTimeout(resolve, 1000));\n\n      // Update credits (trigger gives 10, we add the purchased amount minus the default)\n      const { data: currentCredits } = await supabaseAdmin\n        .from(\"user_credits\")\n        .select(\"credits_balance\")\n        .eq(\"user_id\", userId)\n        .single();\n\n      if (currentCredits) {\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .update({ credits_balance: currentCredits.credits_balance + credits })\n          .eq(\"user_id\", userId);\n      } else {\n        // If trigger didn't fire, create manually\n        await supabaseAdmin\n          .from(\"user_credits\")\n          .insert({ user_id: userId, credits_balance: credits + 4, credits_used: 0 });\n      }\n    }\n\n    // Log the transaction\n    await supabaseAdmin.from(\"credit_transactions\").insert({\n      user_id: userId,\n      amount: credits,\n      type: \"purchase\",\n      description: `Compra de ${credits} créditos via Stripe (${packageId})`,\n    });\n\n    return new Response(\n      JSON.stringify({\n        success: true,\n        isNewUser,\n        tempPassword,\n        email,\n        credits,\n      }),\n      {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 200,\n      }\n    );\n  } catch (error) {\n    console.error(\"handle-payment-success error:\", error);\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
  "process-email-queue": "import { sendLovableEmail } from 'npm:@lovable.dev/email-js'\nimport { createClient } from 'npm:@supabase/supabase-js@2'\n\nconst MAX_RETRIES = 5\nconst DEFAULT_BATCH_SIZE = 10\nconst DEFAULT_SEND_DELAY_MS = 200\nconst DEFAULT_AUTH_TTL_MINUTES = 15\nconst DEFAULT_TRANSACTIONAL_TTL_MINUTES = 60\n\n// Check if an error is a rate-limit (429) response.\n// Uses EmailAPIError.status when available (email-js >=0.x with structured errors),\n// falls back to parsing the error message for older versions.\nfunction isRateLimited(error: unknown): boolean {\n  if (error && typeof error === 'object' && 'status' in error) {\n    return (error as { status: number }).status === 429\n  }\n  return error instanceof Error && error.message.includes('429')\n}\n\n// Check if an error is a forbidden (403) response, which means emails are\n// disabled for this project. Retrying won't help — move straight to DLQ.\nfunction isForbidden(error: unknown): boolean {\n  if (error && typeof error === 'object' && 'status' in error) {\n    return (error as { status: number }).status === 403\n  }\n  return error instanceof Error && error.message.includes('403')\n}\n\n// Extract Retry-After seconds from a structured EmailAPIError, or default to 60s.\nfunction getRetryAfterSeconds(error: unknown): number {\n  if (error && typeof error === 'object' && 'retryAfterSeconds' in error) {\n    return (error as { retryAfterSeconds: number | null }).retryAfterSeconds ?? 60\n  }\n  return 60\n}\n\nfunction parseJwtClaims(token: string): Record<string, unknown> | null {\n  const parts = token.split('.')\n  if (parts.length < 2) {\n    return null\n  }\n\n  try {\n    const payload = parts[1]\n      .replaceAll('-', '+')\n      .replaceAll('_', '/')\n      .padEnd(Math.ceil(parts[1].length / 4) * 4, '=')\n\n    return JSON.parse(atob(payload)) as Record<string, unknown>\n  } catch {\n    return null\n  }\n}\n\n// Move a message to the dead letter queue and log the reason.\nasync function moveToDlq(\n  supabase: ReturnType<typeof createClient>,\n  queue: string,\n  msg: { msg_id: number; message: Record<string, unknown> },\n  reason: string\n): Promise<void> {\n  const payload = msg.message\n  await supabase.from('email_send_log').insert({\n    message_id: payload.message_id,\n    template_name: (payload.label || queue) as string,\n    recipient_email: payload.to,\n    status: 'dlq',\n    error_message: reason,\n  })\n  const { error } = await supabase.rpc('move_to_dlq', {\n    source_queue: queue,\n    dlq_name: `${queue}_dlq`,\n    message_id: msg.msg_id,\n    payload,\n  })\n  if (error) {\n    console.error('Failed to move message to DLQ', { queue, msg_id: msg.msg_id, reason, error })\n  }\n}\n\nDeno.serve(async (req) => {\n  const apiKey = Deno.env.get('LOVABLE_API_KEY')\n  const supabaseUrl = Deno.env.get('SUPABASE_URL')\n  const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')\n\n  if (!apiKey || !supabaseUrl || !supabaseServiceKey) {\n    console.error('Missing required environment variables')\n    return new Response(\n      JSON.stringify({ error: 'Server configuration error' }),\n      { status: 500, headers: { 'Content-Type': 'application/json' } }\n    )\n  }\n\n  const authHeader = req.headers.get('Authorization')\n  if (!authHeader?.startsWith('Bearer ')) {\n    return new Response(\n      JSON.stringify({ error: 'Unauthorized' }),\n      { status: 401, headers: { 'Content-Type': 'application/json' } }\n    )\n  }\n\n  // Defense in depth: verify_jwt=true already requires a valid JWT at the\n  // gateway layer. This adds an explicit role check so only service-role\n  // callers can trigger queue processing.\n  const token = authHeader.slice('Bearer '.length).trim()\n  const claims = parseJwtClaims(token)\n  if (claims?.role !== 'service_role') {\n    return new Response(\n      JSON.stringify({ error: 'Forbidden' }),\n      { status: 403, headers: { 'Content-Type': 'application/json' } }\n    )\n  }\n\n  const supabase = createClient(supabaseUrl, supabaseServiceKey)\n\n  // 1. Check rate-limit cooldown and read queue config\n  const { data: state } = await supabase\n    .from('email_send_state')\n    .select('retry_after_until, batch_size, send_delay_ms, auth_email_ttl_minutes, transactional_email_ttl_minutes')\n    .single()\n\n  if (state?.retry_after_until && new Date(state.retry_after_until) > new Date()) {\n    return new Response(\n      JSON.stringify({ skipped: true, reason: 'rate_limited' }),\n      { headers: { 'Content-Type': 'application/json' } }\n    )\n  }\n\n  const batchSize = state?.batch_size ?? DEFAULT_BATCH_SIZE\n  const sendDelayMs = state?.send_delay_ms ?? DEFAULT_SEND_DELAY_MS\n  const ttlMinutes: Record<string, number> = {\n    auth_emails: state?.auth_email_ttl_minutes ?? DEFAULT_AUTH_TTL_MINUTES,\n    transactional_emails: state?.transactional_email_ttl_minutes ?? DEFAULT_TRANSACTIONAL_TTL_MINUTES,\n  }\n\n  let totalProcessed = 0\n\n  // 2. Process auth_emails first (priority), then transactional_emails\n  for (const queue of ['auth_emails', 'transactional_emails']) {\n    const { data: messages, error: readError } = await supabase.rpc('read_email_batch', {\n      queue_name: queue,\n      batch_size: batchSize,\n      vt: 30,\n    })\n\n    if (readError) {\n      console.error('Failed to read email batch', { queue, error: readError })\n      continue\n    }\n\n    if (!messages?.length) continue\n\n    // Retry budget is based on real send failures, not pgmq read_ct.\n    // read_ct increments for every message in a claimed batch, including\n    // messages not attempted when a 429 stops processing early.\n    const messageIds = Array.from(\n      new Set(\n        messages\n          .map((msg) =>\n            msg?.message?.message_id && typeof msg.message.message_id === 'string'\n              ? msg.message.message_id\n              : null\n          )\n          .filter((id): id is string => Boolean(id))\n      )\n    )\n    const failedAttemptsByMessageId = new Map<string, number>()\n    if (messageIds.length > 0) {\n      const { data: failedRows, error: failedRowsError } = await supabase\n        .from('email_send_log')\n        .select('message_id')\n        .in('message_id', messageIds)\n        .eq('status', 'failed')\n\n      if (failedRowsError) {\n        console.error('Failed to load failed-attempt counters', {\n          queue,\n          error: failedRowsError,\n        })\n      } else {\n        for (const row of failedRows ?? []) {\n          const messageId = row?.message_id\n          if (typeof messageId !== 'string' || !messageId) continue\n          failedAttemptsByMessageId.set(\n            messageId,\n            (failedAttemptsByMessageId.get(messageId) ?? 0) + 1\n          )\n        }\n      }\n    }\n\n    for (let i = 0; i < messages.length; i++) {\n      const msg = messages[i]\n      const payload = msg.message\n      const failedAttempts =\n        payload?.message_id && typeof payload.message_id === 'string'\n          ? (failedAttemptsByMessageId.get(payload.message_id) ?? 0)\n          : 0\n\n      // Drop expired messages (TTL exceeded)\n      if (payload.queued_at) {\n        const ageMs = Date.now() - new Date(payload.queued_at).getTime()\n        const maxAgeMs = ttlMinutes[queue] * 60 * 1000\n        if (ageMs > maxAgeMs) {\n          console.warn('Email expired (TTL exceeded)', {\n            queue,\n            msg_id: msg.msg_id,\n            queued_at: payload.queued_at,\n            ttl_minutes: ttlMinutes[queue],\n          })\n          await moveToDlq(supabase, queue, msg, `TTL exceeded (${ttlMinutes[queue]} minutes)`)\n          continue\n        }\n      }\n\n      // Move to DLQ if max failed send attempts reached.\n      if (failedAttempts >= MAX_RETRIES) {\n        await moveToDlq(supabase, queue, msg, `Max retries (${MAX_RETRIES}) exceeded (attempted ${failedAttempts} times)`)\n        continue\n      }\n\n      // Guard: skip if another worker already sent this message (VT expired race)\n      if (payload.message_id) {\n        const { data: alreadySent } = await supabase\n          .from('email_send_log')\n          .select('id')\n          .eq('message_id', payload.message_id)\n          .eq('status', 'sent')\n          .maybeSingle()\n\n        if (alreadySent) {\n          console.warn('Skipping duplicate send (already sent)', {\n            queue,\n            msg_id: msg.msg_id,\n            message_id: payload.message_id,\n          })\n          const { error: dupDelError } = await supabase.rpc('delete_email', {\n            queue_name: queue,\n            message_id: msg.msg_id,\n          })\n          if (dupDelError) {\n            console.error('Failed to delete duplicate message from queue', { queue, msg_id: msg.msg_id, error: dupDelError })\n          }\n          continue\n        }\n      }\n\n      try {\n        await sendLovableEmail(\n          {\n            run_id: payload.run_id,\n            to: payload.to,\n            from: payload.from,\n            sender_domain: payload.sender_domain,\n            subject: payload.subject,\n            html: payload.html,\n            text: payload.text,\n            purpose: payload.purpose,\n            label: payload.label,\n            idempotency_key: payload.idempotency_key,\n            unsubscribe_token: payload.unsubscribe_token,\n            message_id: payload.message_id,\n          },\n          // sendUrl is optional — when LOVABLE_SEND_URL is not set, the library\n          // falls back to the default Lovable API endpoint (https://api.lovable.dev).\n          // Set LOVABLE_SEND_URL as a Supabase secret to override (e.g. for local dev).\n          { apiKey, sendUrl: Deno.env.get('LOVABLE_SEND_URL') }\n        )\n\n        // Log success\n        await supabase.from('email_send_log').insert({\n          message_id: payload.message_id,\n          template_name: payload.label || queue,\n          recipient_email: payload.to,\n          status: 'sent',\n        })\n\n        // Delete from queue\n        const { error: delError } = await supabase.rpc('delete_email', {\n          queue_name: queue,\n          message_id: msg.msg_id,\n        })\n        if (delError) {\n          console.error('Failed to delete sent message from queue', { queue, msg_id: msg.msg_id, error: delError })\n        }\n        totalProcessed++\n      } catch (error) {\n        const errorMsg = error instanceof Error ? error.message : String(error)\n        console.error('Email send failed', {\n          queue,\n          msg_id: msg.msg_id,\n          read_ct: msg.read_ct,\n          failed_attempts: failedAttempts,\n          error: errorMsg,\n        })\n\n        if (isRateLimited(error)) {\n          await supabase.from('email_send_log').insert({\n            message_id: payload.message_id,\n            template_name: payload.label || queue,\n            recipient_email: payload.to,\n            status: 'rate_limited',\n            error_message: errorMsg.slice(0, 1000),\n          })\n\n          const retryAfterSecs = getRetryAfterSeconds(error)\n          await supabase\n            .from('email_send_state')\n            .update({\n              retry_after_until: new Date(\n                Date.now() + retryAfterSecs * 1000\n              ).toISOString(),\n              updated_at: new Date().toISOString(),\n            })\n            .eq('id', 1)\n\n          // Stop processing — remaining messages stay in queue (VT expires, retried next cycle)\n          return new Response(\n            JSON.stringify({ processed: totalProcessed, stopped: 'rate_limited' }),\n            { headers: { 'Content-Type': 'application/json' } }\n          )\n        }\n\n        // 403 means emails are disabled for this project — retrying won't help.\n        // Move straight to DLQ and stop processing the rest of the batch.\n        if (isForbidden(error)) {\n          await moveToDlq(supabase, queue, msg, 'Emails disabled for this project')\n          return new Response(\n            JSON.stringify({ processed: totalProcessed, stopped: 'emails_disabled' }),\n            { headers: { 'Content-Type': 'application/json' } }\n          )\n        }\n\n        // Log non-429 failures to track real retry attempts.\n        await supabase.from('email_send_log').insert({\n          message_id: payload.message_id,\n          template_name: payload.label || queue,\n          recipient_email: payload.to,\n          status: 'failed',\n          error_message: errorMsg.slice(0, 1000),\n        })\n        if (payload?.message_id && typeof payload.message_id === 'string') {\n          failedAttemptsByMessageId.set(payload.message_id, failedAttempts + 1)\n        }\n\n        // Non-429 errors: message stays invisible until VT expires, then retried\n      }\n\n      // Small delay between sends to smooth bursts\n      if (i < messages.length - 1) {\n        await new Promise((r) => setTimeout(r, sendDelayMs))\n      }\n    }\n  }\n\n  return new Response(\n    JSON.stringify({ processed: totalProcessed }),\n    { headers: { 'Content-Type': 'application/json' } }\n  )\n})\n",
  "update-user-credit": "import { serve } from \"https://deno.land/std@0.190.0/http/server.ts\";\nimport { createClient } from \"npm:@supabase/supabase-js@2.57.2\";\n\nconst corsHeaders = {\n  \"Access-Control-Allow-Origin\": \"*\",\n  \"Access-Control-Allow-Headers\":\n    \"authorization, x-client-info, apikey, content-type, x-webhook-secret\",\n};\n\nconst CREDITS_MAP: Record<string, number> = {\n  \"PACOTE BASICO\": 20,\n  \"PACOTE PRO\": 50,\n  \"PACOTE PLUS\": 100,\n};\n\nserve(async (req) => {\n  if (req.method === \"OPTIONS\") {\n    return new Response(null, { headers: corsHeaders });\n  }\n\n  try {\n    const webhookSecret = req.headers.get(\"x-webhook-secret\");\n    const expectedSecret = Deno.env.get(\"WEBHOOK_SECRET\");\n    if (!expectedSecret || webhookSecret !== expectedSecret) {\n      return new Response(JSON.stringify({ error: \"Unauthorized\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 401,\n      });\n    }\n\n    const { email, packageId } = await req.json();\n\n    if (!email || !packageId) {\n      return new Response(JSON.stringify({ error: \"email e packageId são obrigatórios\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const credits = CREDITS_MAP[packageId];\n    if (!credits) {\n      return new Response(JSON.stringify({ error: \"packageId inválido. Use: PACOTE BASICO, PACOTE PRO, PACOTE PLUS\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 400,\n      });\n    }\n\n    const supabaseAdmin = createClient(\n      Deno.env.get(\"SUPABASE_URL\") ?? \"\",\n      Deno.env.get(\"SUPABASE_SERVICE_ROLE_KEY\") ?? \"\"\n    );\n\n    // Find user by email\n    const { data: { users }, error: listError } = await supabaseAdmin.auth.admin.listUsers();\n    if (listError) throw listError;\n\n    const user = users?.find((u) => u.email === email);\n    if (!user) {\n      return new Response(JSON.stringify({ error: \"Usuário não encontrado\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 404,\n      });\n    }\n\n    // Get current balance\n    const { data: currentCredits } = await supabaseAdmin\n      .from(\"user_credits\")\n      .select(\"credits_balance\")\n      .eq(\"user_id\", user.id)\n      .single();\n\n    if (!currentCredits) {\n      return new Response(JSON.stringify({ error: \"Registro de créditos não encontrado\" }), {\n        headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n        status: 404,\n      });\n    }\n\n    const newBalance = currentCredits.credits_balance + credits;\n\n    // Update balance\n    await supabaseAdmin\n      .from(\"user_credits\")\n      .update({ credits_balance: newBalance })\n      .eq(\"user_id\", user.id);\n\n    // Log transaction\n    await supabaseAdmin.from(\"credit_transactions\").insert({\n      user_id: user.id,\n      amount: credits,\n      type: \"purchase\",\n      description: `Compra de ${credits} créditos via Hotmart (${packageId})`,\n    });\n\n    return new Response(\n      JSON.stringify({\n        success: true,\n        email,\n        packageId,\n        creditsAdded: credits,\n        newBalance,\n      }),\n      { headers: { ...corsHeaders, \"Content-Type\": \"application/json\" }, status: 200 }\n    );\n  } catch (error) {\n    console.error(\"update-user-credit error:\", error);\n    return new Response(JSON.stringify({ error: error.message }), {\n      headers: { ...corsHeaders, \"Content-Type\": \"application/json\" },\n      status: 500,\n    });\n  }\n});\n",
};
